export function findRepoRoot(cwd: string, git: GitClient): { repoRoot: string; hasGit: boolean } {
	const gitRoot = git.getRepoRoot(cwd);
	if (gitRoot) {
		return { repoRoot: gitRoot, hasGit: true };
	}

	let current = path.resolve(cwd);
	while (true) {
		if (existsSync(path.join(current, ".specify"))) {
			return { repoRoot: current, hasGit: false };
		}
		const parent = path.dirname(current);
		if (parent === current) {
			return { repoRoot: path.resolve(cwd), hasGit: false };
		}
		current = parent;
	}
}

export function listFeatureDirs(repoRoot: string): string[] {
	const specsDir = path.join(repoRoot, "specs");
	if (!existsSync(specsDir)) {
		return [];
	}

	return readdirSync(specsDir)
		.filter((entry) => /^\d{3}-/.test(entry))
		.filter((entry) => {
			const fullPath = path.join(specsDir, entry);
			return existsSync(fullPath) && statSync(fullPath).isDirectory();
		})
		.sort((a, b) => a.localeCompare(b));
}

export function getLatestFeatureDir(repoRoot: string): string | undefined {
	const features = listFeatureDirs(repoRoot);
	return features.at(-1);
}

export function extractFeatureNumber(value: string): number | null {
	const match = value.match(/^(\d{3})-/);
	if (!match) {
		return null;
	}
	return Number.parseInt(match[1], 10);
}

export function resolveFeatureFromBranch(repoRoot: string, branchName: string): string | undefined {
	const prefix = branchName.match(/^(\d{3})-/)?.[1];
	if (!prefix) {
		return undefined;
	}
	const matches = listFeatureDirs(repoRoot).filter((entry) => entry.startsWith(`${prefix}-`));
	if (matches.length === 1) {
		return matches[0];
	}
	return matches.find((entry) => entry === branchName) ?? undefined;
}

export function buildWorkflowPaths(repoRoot: string, featureName?: string): WorkflowPaths {
	const specifyDir = path.join(repoRoot, ".specify");
	const templatesDir = path.join(specifyDir, "templates");
	const memoryDir = path.join(specifyDir, "memory");
	const featureDir = featureName ? path.join(repoRoot, "specs", featureName) : undefined;
	return {
		repoRoot,
		specsDir: path.join(repoRoot, "specs"),
		specifyDir,
		templatesDir,
		memoryDir,
		constitutionFile: path.join(memoryDir, "constitution.md"),
		agentContextFile: path.join(memoryDir, "pi-agent.md"),
		extensionsConfigFile: path.join(specifyDir, "extensions.yml"),
		workflowReadmeFile: path.join(specifyDir, "README.md"),
		featureDir,
		featureBranch: featureName,
		featureNumber: featureName?.match(/^(\d{3})-/)?.[1],
		featureSpec: featureDir ? path.join(featureDir, "spec.md") : undefined,
		planFile: featureDir ? path.join(featureDir, "plan.md") : undefined,
		tasksFile: featureDir ? path.join(featureDir, "tasks.md") : undefined,
		researchFile: featureDir ? path.join(featureDir, "research.md") : undefined,
		dataModelFile: featureDir ? path.join(featureDir, "data-model.md") : undefined,
		quickstartFile: featureDir ? path.join(featureDir, "quickstart.md") : undefined,
		contractsDir: featureDir ? path.join(featureDir, "contracts") : undefined,
		checklistsDir: featureDir ? path.join(featureDir, "checklists") : undefined,
	};
}

export function cleanBranchSegment(value: string): string {
	return value
		.toLowerCase()
		.replace(/[^a-z0-9]+/g, "-")
		.replace(/-+/g, "-")
		.replace(/^-|-$/g, "");
}

export function generateBranchShortName(description: string): string {
	const tokens = description.match(/[A-Za-z0-9]+/g) ?? [];
	const meaningful: string[] = [];

	for (const original of tokens) {
		const normalized = original.toLowerCase();
		if (!normalized || STOP_WORDS.has(normalized)) {
			continue;
		}

		const isAcronymLike = /[A-Z]{2,}/.test(original) || /\d/.test(original);
		if (normalized.length >= 3 || isAcronymLike) {
			meaningful.push(normalized);
		}
	}

	const selected = (meaningful.length > 0 ? meaningful : tokens.map((token) => token.toLowerCase()))
		.filter(Boolean)
		.slice(0, meaningful.length === 4 ? 4 : 3);

	const fallback = selected.join("-") || "feature";
	return cleanBranchSegment(fallback) || "feature";
}

export function truncateBranchName(branchName: string): string {
	const MAX_BRANCH_LENGTH = 244;
	if (branchName.length <= MAX_BRANCH_LENGTH) {
		return branchName;
	}
	const prefix = branchName.slice(0, 4);
	const suffix = branchName.slice(4, MAX_BRANCH_LENGTH).replace(/-+$/g, "");
	return `${prefix}${suffix}`;
}

export function computeNextFeatureNumber(repoRoot: string, branches: string[]): number {
	const featureNumbers = [
		...listFeatureDirs(repoRoot)
			.map((entry) => extractFeatureNumber(entry))
			.filter((value): value is number => value != null),
		...branches
			.map((entry) => entry.replace(/^[^/]+\//, ""))
			.map((entry) => extractFeatureNumber(entry))
			.filter((value): value is number => value != null),
	];
	const highest = featureNumbers.length > 0 ? Math.max(...featureNumbers) : 0;
	return highest + 1;
}

export function prepareFeatureWorkspace(options: {
	repoRoot: string;
	description: string;
	git: GitClient;
	currentBranch: string;
	hasGit: boolean;
	shortName?: string;
}): PreparedFeature {
	const featureNumber = String(
		computeNextFeatureNumber(options.repoRoot, options.git.listBranches(options.repoRoot)),
	).padStart(3, "0");
	const branchSuffix =
		cleanBranchSegment(options.shortName || generateBranchShortName(options.description)) || "feature";
	const branchName = truncateBranchName(`${featureNumber}-${branchSuffix}`);
	const featureDir = path.join(options.repoRoot, "specs", branchName);
	const specFile = path.join(featureDir, "spec.md");
	const checklistsDir = path.join(featureDir, "checklists");

	mkdirSync(featureDir, { recursive: true });
	mkdirSync(checklistsDir, { recursive: true });

	let createdBranch = false;
	if (options.hasGit) {
		if (options.currentBranch !== branchName) {
			options.git.createAndSwitchBranch(options.repoRoot, branchName);
			createdBranch = true;
		}
	}

	return {
		branchName,
		featureNumber,
		featureDir,
		specFile,
		checklistsDir,
		createdBranch,
	};
}

import { copyFileSync, existsSync, mkdirSync, readdirSync, readFileSync, statSync, writeFileSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import type { WorkflowPaths } from "./types.js";

const WORKFLOW_README = `# Native /spec Workflow

This project uses the native pi spec workflow inspired by GitHub spec-kit.

## Core commands

- /spec init
- /spec constitution <principles>
- /spec specify <feature description>
- /spec clarify [focus]
- /spec checklist [domain]
- /spec plan <technical context>
- /spec tasks [context]
- /spec analyze [focus]
- /spec implement [focus]
- /spec status
- /spec next

## Runtime notes

- The pi extension handles feature numbering, branch naming, path resolution, and file scaffolding in TypeScript.
- Workflow templates live in .specify/templates/commands/ and can be customized per project.
- File templates live in .specify/templates/.
- The native replacement for agent-specific context files is .specify/memory/pi-agent.md.
- Feature artifacts live in specs/###-feature-name/.
`;

const DEFAULT_EXTENSIONS_YML = `settings:
  auto_execute_hooks: true
hooks: {}
`;

function getExtensionRoot(): string {
	return path.dirname(fileURLToPath(import.meta.url));
}

function getBundledTemplatesRoot(): string {
	return path.join(getExtensionRoot(), "assets", "templates");
}

function ensureDir(dir: string): void {
	mkdirSync(dir, { recursive: true });
}

function copyDirIfMissing(sourceDir: string, targetDir: string): void {
	ensureDir(targetDir);
	for (const entry of readdirSync(sourceDir)) {
		const sourcePath = path.join(sourceDir, entry);
		const targetPath = path.join(targetDir, entry);
		const sourceStat = statSync(sourcePath);
		if (sourceStat.isDirectory()) {
			copyDirIfMissing(sourcePath, targetPath);
			continue;
		}
		if (!existsSync(targetPath)) {
			copyFileSync(sourcePath, targetPath);
		}
	}
}

export function ensureWorkflowScaffold(paths: WorkflowPaths): string[] {
	const created: string[] = [];
	ensureDir(paths.specifyDir);
	ensureDir(paths.specsDir);
	ensureDir(paths.templatesDir);
	ensureDir(paths.memoryDir);

	const beforeTemplates = new Set<string>();
	if (existsSync(paths.templatesDir)) {
		for (const entry of readdirSync(paths.templatesDir)) {
			beforeTemplates.add(entry);
		}
	}

	copyDirIfMissing(getBundledTemplatesRoot(), paths.templatesDir);

	for (const entry of readdirSync(paths.templatesDir)) {
		if (!beforeTemplates.has(entry)) {
			created.push(path.join(paths.templatesDir, entry));
		}
	}

	if (!existsSync(paths.workflowReadmeFile)) {
		writeFileSync(paths.workflowReadmeFile, WORKFLOW_README, "utf8");
		created.push(paths.workflowReadmeFile);
	}
	if (!existsSync(paths.extensionsConfigFile)) {
		writeFileSync(paths.extensionsConfigFile, DEFAULT_EXTENSIONS_YML, "utf8");
		created.push(paths.extensionsConfigFile);
	}
	if (!existsSync(paths.constitutionFile)) {
		const template = readFileSync(path.join(paths.templatesDir, "constitution-template.md"), "utf8");
		writeFileSync(paths.constitutionFile, template, "utf8");
		created.push(paths.constitutionFile);
	}
	if (!existsSync(paths.agentContextFile)) {
		const template = readFileSync(path.join(paths.templatesDir, "agent-file-template.md"), "utf8");
		writeFileSync(paths.agentContextFile, template, "utf8");
		created.push(paths.agentContextFile);
	}

	return created;
}

export function ensureFeatureArtifacts(paths: WorkflowPaths): string[] {
	if (!(paths.featureDir && paths.featureSpec && paths.checklistsDir)) {
		return [];
	}

	const created: string[] = [];
	ensureDir(paths.featureDir);
	ensureDir(paths.checklistsDir);
	if (!existsSync(paths.featureSpec)) {
		const template = readFileSync(path.join(paths.templatesDir, "spec-template.md"), "utf8");
		writeFileSync(paths.featureSpec, template, "utf8");
		created.push(paths.featureSpec);
	}
	return created;
}

export function ensurePlanArtifact(paths: WorkflowPaths): string[] {
	if (!(paths.featureDir && paths.planFile && paths.contractsDir)) {
		return [];
	}

	const created: string[] = [];
	ensureDir(paths.featureDir);
	ensureDir(paths.contractsDir);
	if (!existsSync(paths.planFile)) {
		const template = readFileSync(path.join(paths.templatesDir, "plan-template.md"), "utf8");
		writeFileSync(paths.planFile, template, "utf8");
		created.push(paths.planFile);
	}
	return created;
}

export function getWorkflowTemplatePath(paths: WorkflowPaths, name: string): string {
	return path.join(paths.templatesDir, "commands", `${name}.md`);
}

export function formatCreatedFiles(created: string[]): string {
	if (created.length === 0) {
		return "No new scaffold files were needed.";
	}
	return `Created ${created.length} scaffold file(s):\n${created.map((file) => `- ${file}`).join("\n")}`;
}

import type { ExtensionAPI, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import { Text } from "@mariozechner/pi-tui";
import { getStatus, syncFeature, syncTasks } from "./linear.js";
import { createVcsClient } from "./vcs.js";
import { buildWorkflowPrompt, getStepNotes } from "./prompts.js";
import {
	ensureFeatureArtifacts,
	ensurePlanArtifact,
	ensureWorkflowScaffold,
	formatCreatedFiles,
	getWorkflowTemplatePath,
} from "./scaffold.js";
import {
	buildWorkflowStatus,
	formatFeatureList,
	formatHelpReport,
	formatWorkflowStatus,
	summarizeChecklists,
} from "./status.js";
import { SPEC_SUBCOMMANDS, type SpecSubcommand, type WorkflowPaths, type WorkflowStep } from "./types.js";
import {
	buildWorkflowPaths,
	findRepoRoot,
	getLatestFeatureDir,
	listFeatureDirs,
	prepareFeatureWorkspace,
	resolveFeatureFromBranch,
} from "./workspace.js";

const REPORT_MESSAGE_TYPE = "pi-spec-report";
const PROMPT_OPTIONAL_STEPS = new Set<WorkflowStep>(["clarify", "tasks", "analyze", "implement"]);

function tokenize(input: string): { subcommand: SpecSubcommand | null; remainder: string } {
	const trimmed = input.trim();
	if (!trimmed) {
		return { subcommand: "status", remainder: "" };
	}
	const [raw, ...rest] = trimmed.split(/\s+/);
	const normalized = raw.toLowerCase();
	if ((SPEC_SUBCOMMANDS as readonly string[]).includes(normalized)) {
		return { subcommand: normalized as SpecSubcommand, remainder: rest.join(" ").trim() };
	}
	return { subcommand: null, remainder: trimmed };
}

function sendReport(pi: ExtensionAPI, content: string): void {
	pi.sendMessage({ customType: REPORT_MESSAGE_TYPE, content, display: true });
}

function isWorkflowStep(subcommand: SpecSubcommand): subcommand is WorkflowStep {
	return ["constitution", "specify", "clarify", "checklist", "plan", "tasks", "analyze", "implement"].includes(
		subcommand,
	);
}

async function promptForMissingInput(
	ctx: ExtensionCommandContext,
	title: string,
	placeholder: string,
): Promise<string | undefined> {
	if (!ctx.hasUI) {
		return undefined;
	}
	if (typeof ctx.ui.editor === "function") {
		const response = await ctx.ui.editor(title, placeholder);
		return response?.trim() || undefined;
	}
	if (typeof ctx.ui.input === "function") {
		const response = await ctx.ui.input(title, placeholder);
		return response?.trim() || undefined;
	}
	return undefined;
}

function stepNeedsRequiredInput(step: WorkflowStep): boolean {
	return !PROMPT_OPTIONAL_STEPS.has(step);
}

async function resolveActiveFeatureName(
	ctx: ExtensionCommandContext,
	repoRoot: string,
	currentBranch: string,
	hasGit = true,
): Promise<string | undefined> {
	const featureFromBranch = resolveFeatureFromBranch(repoRoot, currentBranch);
	if (featureFromBranch) {
		return featureFromBranch;
	}

	// When git is available, the current branch is the source of truth for the
	// active feature — matching upstream spec-kit behavior.  The specs/ directory
	// scan is only a fallback for non-git repositories where branch detection is
	// unavailable.
	if (hasGit) {
		return undefined;
	}

	const features = listFeatureDirs(repoRoot);
	if (features.length === 0) {
		return undefined;
	}
	if (features.length === 1) {
		return features[0];
	}
	if (!ctx.hasUI || typeof ctx.ui.select !== "function") {
		return getLatestFeatureDir(repoRoot);
	}
	const selected = await ctx.ui.select("Select active spec feature", features);
	return selected || undefined;
}

async function resolveFeaturePaths(
	ctx: ExtensionCommandContext,
	repoRoot: string,
	currentBranch: string,
	hasGit = true,
): Promise<WorkflowPaths | undefined> {
	const featureName = await resolveActiveFeatureName(ctx, repoRoot, currentBranch, hasGit);
	if (!featureName) {
		ctx.ui.notify("No active feature found. Run /spec specify <feature description> first.", "warning");
		return undefined;
	}
	return buildWorkflowPaths(repoRoot, featureName);
}

function queueWorkflow(
	pi: ExtensionAPI,
	step: WorkflowStep,
	currentBranch: string,
	paths: WorkflowPaths,
	input: string,
): void {
	const prompt = buildWorkflowPrompt({
		step,
		input,
		paths,
		currentBranch,
		workflowTemplatePath: getWorkflowTemplatePath(paths, step),
		stepNotes: getStepNotes(step),
		checklists: step === "implement" ? summarizeChecklists(paths.checklistsDir) : undefined,
	});
	pi.sendUserMessage(prompt);
}

async function collectStepInput(ctx: ExtensionCommandContext, step: WorkflowStep, existing: string): Promise<string> {
	if (existing.trim() || !stepNeedsRequiredInput(step)) {
		return existing.trim();
	}

	const titleByStep: Record<WorkflowStep, string> = {
		constitution: "Describe the constitution principles",
		specify: "Describe the feature to specify",
		clarify: "Optional clarification focus",
		checklist: "Optional checklist focus or domain",
		plan: "Describe the technical context",
		tasks: "Optional task-generation context",
		analyze: "Optional analysis focus",
		implement: "Optional implementation focus",
	};

	return (
		(await promptForMissingInput(ctx, titleByStep[step], "Write the details for this /spec step here")) ?? ""
	).trim();
}

function makeEnv(ctx: ExtensionCommandContext, git = createVcsClient(ctx.cwd)) {
	const { repoRoot, hasGit } = findRepoRoot(ctx.cwd, git);
	const currentBranch = git.getCurrentBranch(repoRoot) ?? process.env.SPECIFY_FEATURE ?? "main";
	const basePaths = buildWorkflowPaths(repoRoot);
	return { git, repoRoot, hasGit, currentBranch, basePaths };
}

function handleInit(pi: ExtensionAPI, repoRoot: string, created: string[]): void {
	sendReport(
		pi,
		[
			"# /spec init",
			"",
			`- Repository root: ${repoRoot}`,
			formatCreatedFiles(created),
			"",
			"Next: `/spec constitution <principles>` or `/spec specify <feature description>`.",
		].join("\n"),
	);
}

async function handleStatus(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	repoRoot: string,
	currentBranch: string,
	hasGit: boolean,
): Promise<void> {
	const activeFeature = await resolveActiveFeatureName(ctx, repoRoot, currentBranch, hasGit);
	sendReport(
		pi,
		formatWorkflowStatus(
			buildWorkflowStatus({
				repoRoot,
				currentBranch,
				paths: buildWorkflowPaths(repoRoot, activeFeature),
				activeFeature,
			}),
		),
	);
}

async function handleNext(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	repoRoot: string,
	currentBranch: string,
	hasGit: boolean,
): Promise<void> {
	const activeFeature = await resolveActiveFeatureName(ctx, repoRoot, currentBranch, hasGit);
	const status = buildWorkflowStatus({
		repoRoot,
		currentBranch,
		paths: buildWorkflowPaths(repoRoot, activeFeature),
		activeFeature,
	});
	sendReport(pi, `# Next /spec steps\n\n${status.nextSteps.map((step) => `- ${step}`).join("\n")}`);
}

function handleSpecify(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
	input: string,
): void {
	if (!input) {
		ctx.ui.notify("/spec specify requires a feature description.", "warning");
		return;
	}

	try {
		const prepared = prepareFeatureWorkspace({
			repoRoot: env.repoRoot,
			description: input,
			git: env.git,
			currentBranch: env.currentBranch,
			hasGit: env.hasGit,
		});
		const paths = buildWorkflowPaths(env.repoRoot, prepared.branchName);
		ensureWorkflowScaffold(paths);
		ensureFeatureArtifacts(paths);
		queueWorkflow(pi, "specify", prepared.branchName, paths, input);
		sendReport(
			pi,
			[
				"# /spec specify",
				"",
				`- Feature branch: ${prepared.branchName}`,
				`- Feature number: ${prepared.featureNumber}`,
				`- Feature directory: ${prepared.featureDir}`,
				`- Spec file: ${prepared.specFile}`,
				"",
				"Queued the native specification workflow as a user message.",
			].join("\n"),
		);
	} catch (error) {
		ctx.ui.notify(
			`Failed to prepare feature workspace: ${error instanceof Error ? error.message : String(error)}`,
			"error",
		);
	}
}

async function confirmChecklistOverride(ctx: ExtensionCommandContext, paths: WorkflowPaths): Promise<boolean> {
	const checklists = summarizeChecklists(paths.checklistsDir);
	if (
		!(checklists.some((checklist) => checklist.incomplete > 0) && ctx.hasUI && typeof ctx.ui.confirm === "function")
	) {
		return true;
	}

	const proceed = await ctx.ui.confirm(
		"Incomplete spec checklists",
		`${checklists.map((checklist) => `${checklist.name}: ${checklist.incomplete} incomplete item(s)`).join("\n")}

Proceed with implementation anyway?`,
	);
	if (!proceed) {
		ctx.ui.notify("Implementation cancelled until the checklist review is complete.", "info");
	}
	return proceed;
}

async function handleWorkflowStep(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
	step: WorkflowStep,
	input: string,
): Promise<void> {
	if (step === "specify") {
		handleSpecify(pi, ctx, env, input);
		return;
	}

	const featurePaths =
		step === "constitution"
			? buildWorkflowPaths(
					env.repoRoot,
					await resolveActiveFeatureName(ctx, env.repoRoot, env.currentBranch, env.hasGit),
				)
			: await resolveFeaturePaths(ctx, env.repoRoot, env.currentBranch, env.hasGit);
	ensureWorkflowScaffold(featurePaths ?? env.basePaths);
	if (!featurePaths) {
		return;
	}

	if (step === "plan") {
		ensurePlanArtifact(featurePaths);
	}
	if (step === "implement" && !(await confirmChecklistOverride(ctx, featurePaths))) {
		return;
	}

	queueWorkflow(pi, step, env.currentBranch, featurePaths, input);
	ctx.ui.notify(`Queued /spec ${step} workflow.`, "info");
}

async function handleLinear(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
	linearSubcommand: string,
): Promise<void> {
	// Parse linear subcommand (sync-feature, sync-tasks, status)
	const normalized = linearSubcommand.toLowerCase().trim();

	// Resolve active feature
	const featurePaths = await resolveFeaturePaths(ctx, env.repoRoot, env.currentBranch, env.hasGit);
	if (!featurePaths) {
		return;
	}

	try {
		if (normalized === "sync-feature") {
			await syncFeature(ctx, featurePaths, pi);
		} else if (normalized === "sync-tasks") {
			await syncTasks(ctx, featurePaths, pi);
		} else if (normalized === "status") {
			await getStatus(ctx, featurePaths, pi);
		} else {
			ctx.ui.notify(
				`Unknown /spec linear subcommand: ${linearSubcommand}\n` +
					"Available: sync-feature, sync-tasks, status",
				"warning",
			);
		}
	} catch (error) {
		const message = error instanceof Error ? error.message : String(error);
		ctx.ui.notify(`Linear operation failed: ${message}`, "error");
	}
}

export default function specExtension(pi: ExtensionAPI) {
	pi.registerMessageRenderer(REPORT_MESSAGE_TYPE, (message, _options, theme) => {
		const text = `${theme.fg("accent", theme.bold("spec"))}\n\n${String(message.content ?? "")}`;
		return new Text(text, 0, 0);
	});

	pi.registerCommand("spec", {
		description:
			"Native spec-kit workflow for pi (/spec init|constitution|specify|clarify|checklist|plan|tasks|analyze|implement)",
		getArgumentCompletions(prefix) {
			const trimmed = prefix.trimStart();
			if (trimmed.includes(" ")) {
				return null;
			}
			const values = SPEC_SUBCOMMANDS.filter((command) => command.startsWith(trimmed)).map((command) => ({
				value: command,
				label: command,
			}));
			return values.length > 0 ? values : null;
		},
		handler: async (rawArgs, ctx) => {
			const { subcommand, remainder } = tokenize(rawArgs);
			if (!subcommand) {
				ctx.ui.notify(`Unknown /spec subcommand: ${rawArgs.trim()}`, "warning");
				sendReport(pi, formatHelpReport());
				return;
			}

			const env = makeEnv(ctx);
			if (subcommand === "init") {
				handleInit(pi, env.repoRoot, ensureWorkflowScaffold(env.basePaths));
				return;
			}
			if (subcommand === "help") {
				sendReport(pi, formatHelpReport());
				return;
			}
			if (subcommand === "list") {
				sendReport(pi, formatFeatureList(env.repoRoot));
				return;
			}
			if (subcommand === "status") {
				await handleStatus(pi, ctx, env.repoRoot, env.currentBranch, env.hasGit);
				return;
			}
			if (subcommand === "next") {
				await handleNext(pi, ctx, env.repoRoot, env.currentBranch, env.hasGit);
				return;
			}
			if (subcommand === "linear") {
				await handleLinear(pi, ctx, env, remainder);
				return;
			}
			if (!isWorkflowStep(subcommand)) {
				sendReport(pi, formatHelpReport());
				return;
			}

			const input = await collectStepInput(ctx, subcommand, remainder);
			await handleWorkflowStep(pi, ctx, env, subcommand, input);
		},
	});
}

import { existsSync, readdirSync, readFileSync, statSync } from "node:fs";
import path from "node:path";
import type { ChecklistSummary, WorkflowPaths, WorkflowStatus } from "./types.js";
import { getLatestFeatureDir, listFeatureDirs } from "./workspace.js";

function countChecklistItems(content: string): { total: number; completed: number; incomplete: number } {
	const lines = content.split(/\r?\n/);
	let total = 0;
	let completed = 0;
	let incomplete = 0;
	for (const line of lines) {
		if (/^- \[(?: |x|X)\]/.test(line)) {
			total++;
			if (/^- \[(?:x|X)\]/.test(line)) {
				completed++;
			} else {
				incomplete++;
			}
		}
	}
	return { total, completed, incomplete };
}

export function summarizeChecklists(checklistsDir?: string): ChecklistSummary[] {
	if (!(checklistsDir && existsSync(checklistsDir))) {
		return [];
	}

	return readdirSync(checklistsDir)
		.filter((entry) => entry.endsWith(".md"))
		.map((entry) => {
			const fullPath = path.join(checklistsDir, entry);
			const content = readFileSync(fullPath, "utf8");
			const counts = countChecklistItems(content);
			return {
				name: entry,
				path: fullPath,
				...counts,
				status: counts.incomplete === 0 ? "pass" : "fail",
			} satisfies ChecklistSummary;
		})
		.sort((a, b) => a.name.localeCompare(b.name));
}

function nextStepsFor(paths: WorkflowPaths, initialized: boolean): string[] {
	if (!initialized) {
		return ["/spec init", "/spec constitution <principles>", "/spec specify <feature description>"];
	}

	if (!(paths.featureDir && paths.featureSpec)) {
		return ["/spec specify <feature description>", "/spec list"];
	}

	const steps: string[] = [];
	const specExists = existsSync(paths.featureSpec);
	const planExists = !!paths.planFile && existsSync(paths.planFile);
	const tasksExist = !!paths.tasksFile && existsSync(paths.tasksFile);
	const checklists = summarizeChecklists(paths.checklistsDir);
	const hasIncompleteChecklist = checklists.some((checklist) => checklist.incomplete > 0);

	if (!specExists) {
		steps.push("/spec specify <feature description>");
		return steps;
	}

	steps.push("/spec clarify");
	steps.push("/spec checklist quality");

	if (!planExists) {
		steps.push("/spec plan <technical context>");
		return steps;
	}

	if (!tasksExist) {
		steps.push("/spec tasks");
		return steps;
	}

	steps.push("/spec analyze");
	steps.push(hasIncompleteChecklist ? "/spec implement (after checklist review)" : "/spec implement");
	return steps;
}

export function buildWorkflowStatus(options: {
	repoRoot: string;
	currentBranch: string;
	paths: WorkflowPaths;
	activeFeature?: string;
}): WorkflowStatus {
	const featureDirs = listFeatureDirs(options.repoRoot);
	const activeFeature = options.activeFeature ?? getLatestFeatureDir(options.repoRoot);
	const initialized = existsSync(options.paths.specifyDir);
	const artifacts = [
		{
			label: ".specify/README.md",
			path: options.paths.workflowReadmeFile,
			exists: existsSync(options.paths.workflowReadmeFile),
		},
		{
			label: "constitution.md",
			path: options.paths.constitutionFile,
			exists: existsSync(options.paths.constitutionFile),
		},
		{ label: "pi-agent.md", path: options.paths.agentContextFile, exists: existsSync(options.paths.agentContextFile) },
		{
			label: "extensions.yml",
			path: options.paths.extensionsConfigFile,
			exists: existsSync(options.paths.extensionsConfigFile),
		},
	];

	if (options.paths.featureSpec) {
		artifacts.push({
			label: "spec.md",
			path: options.paths.featureSpec,
			exists: existsSync(options.paths.featureSpec),
		});
	}
	if (options.paths.planFile) {
		artifacts.push({ label: "plan.md", path: options.paths.planFile, exists: existsSync(options.paths.planFile) });
	}
	if (options.paths.tasksFile) {
		artifacts.push({ label: "tasks.md", path: options.paths.tasksFile, exists: existsSync(options.paths.tasksFile) });
	}
	if (options.paths.researchFile) {
		artifacts.push({
			label: "research.md",
			path: options.paths.researchFile,
			exists: existsSync(options.paths.researchFile),
		});
	}
	if (options.paths.dataModelFile) {
		artifacts.push({
			label: "data-model.md",
			path: options.paths.dataModelFile,
			exists: existsSync(options.paths.dataModelFile),
		});
	}
	if (options.paths.quickstartFile) {
		artifacts.push({
			label: "quickstart.md",
			path: options.paths.quickstartFile,
			exists: existsSync(options.paths.quickstartFile),
		});
	}
	if (options.paths.contractsDir) {
		artifacts.push({
			label: "contracts/",
			path: options.paths.contractsDir,
			exists: existsSync(options.paths.contractsDir) && statSync(options.paths.contractsDir).isDirectory(),
		});
	}

	return {
		initialized,
		repoRoot: options.repoRoot,
		currentBranch: options.currentBranch,
		featureDirs,
		activeFeature,
		paths: options.paths,
		artifacts,
		checklists: summarizeChecklists(options.paths.checklistsDir),
		nextSteps: nextStepsFor(options.paths, initialized),
	};
}

export function formatWorkflowStatus(status: WorkflowStatus): string {
	const lines = [
		"# /spec workflow status",
		"",
		`- Repository root: ${status.repoRoot}`,
		`- Initialized: ${status.initialized ? "yes" : "no"}`,
		`- Current branch: ${status.currentBranch}`,
		`- Active feature: ${status.activeFeature ?? "(none)"}`,
		`- Known features: ${status.featureDirs.length > 0 ? status.featureDirs.join(", ") : "(none)"}`,
		"",
		"## Artifacts",
	];

	for (const artifact of status.artifacts) {
		lines.push(`- ${artifact.exists ? "[x]" : "[ ]"} ${artifact.label} — ${artifact.path}`);
	}

	lines.push("", "## Checklist status");
	if (status.checklists.length === 0) {
		lines.push("- No checklist files found.");
	} else {
		for (const checklist of status.checklists) {
			lines.push(
				`- ${checklist.status === "pass" ? "[ok]" : "[!]"} ${checklist.name}: ${checklist.completed}/${checklist.total} complete (${checklist.incomplete} incomplete)`,
			);
		}
	}

	lines.push("", "## Next steps");
	for (const step of status.nextSteps) {
		lines.push(`- ${step}`);
	}
	return lines.join("\n");
}

export function formatHelpReport(): string {
	return [
		"# Native /spec workflow",
		"",
		"Use `/spec` with one of these subcommands:",
		"",
		"- `/spec init` — scaffold `.specify/`, templates, and memory files",
		"- `/spec constitution <principles>` — create or amend the project constitution",
		"- `/spec specify <feature description>` — create a numbered feature branch and spec scaffold",
		"- `/spec clarify [focus]` — resolve critical ambiguities in the active spec",
		"- `/spec checklist [domain]` — generate a requirements-quality checklist",
		"- `/spec plan <technical context>` — build the implementation plan and design artifacts",
		"- `/spec tasks [context]` — derive an executable tasks.md ordered by user story",
		"- `/spec analyze [focus]` — run a read-only cross-artifact consistency review",
		"- `/spec implement [focus]` — execute the plan from tasks.md and mark completed tasks",
		"- `/spec status` — show current workflow state",
		"- `/spec next` — show the next recommended command",
		"- `/spec list` — list all known feature directories",
		"",
		"Tip: `/spec` with no arguments shows the current workflow status.",
	].join("\n");
}

export function formatFeatureList(repoRoot: string): string {
	const features = listFeatureDirs(repoRoot);
	if (features.length === 0) {
		return "# Known features\n\n- No feature directories found yet.";
	}
	return `# Known features\n\n${features.map((feature) => `- ${feature}`).join("\n")}`;
}

import { mkdirSync } from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, describe, expect, it } from "vitest";
import type { GitClient } from "../extension/git.js";
import {
	buildWorkflowPaths,
	cleanBranchSegment,
	computeNextFeatureNumber,
	extractFeatureNumber,
	findRepoRoot,
	generateBranchShortName,
	listFeatureDirs,
	resolveFeatureFromBranch,
	truncateBranchName,
} from "../extension/workspace.js";

const tempDirs: string[] = [];

function createTempDir(prefix: string): string {
	const dir = path.join(os.tmpdir(), `${prefix}-${Math.random().toString(36).slice(2, 8)}`);
	mkdirSync(dir, { recursive: true });
	tempDirs.push(dir);
	return dir;
}

function createGitMock(overrides: Partial<GitClient> = {}): GitClient {
	return {
		getRepoRoot: () => null,
		getCurrentBranch: () => null,
		listBranches: () => [],
		isDirty: () => false,
		createAndSwitchBranch: () => undefined,
		...overrides,
	};
}

afterEach(async () => {
	const { rm } = await import("node:fs/promises");
	await Promise.all(tempDirs.map((dir) => rm(dir, { recursive: true, force: true })));
	tempDirs.length = 0;
});

describe("workspace helpers", () => {
	it("generates a concise branch short name", () => {
		expect(generateBranchShortName("Implement OAuth2 integration for the API")).toContain("oauth2");
		expect(generateBranchShortName("Add a dashboard for analytics")).toBe("dashboard-analytics");
	});

	it("cleans arbitrary branch segments", () => {
		expect(cleanBranchSegment("  Add User Auth!  ")).toBe("add-user-auth");
	});

	it("truncates overlong branch names to GitHub-safe length", () => {
		const input = `001-${"very-long-".repeat(40)}`;
		const result = truncateBranchName(input);
		expect(result.length).toBeLessThanOrEqual(244);
		expect(result.startsWith("001-")).toBe(true);
	});

	it("lists numbered feature directories and resolves them from the current branch", () => {
		const repoRoot = createTempDir("pi-spec-workspace");
		mkdirSync(path.join(repoRoot, "specs", "001-auth-flow"), { recursive: true });
		mkdirSync(path.join(repoRoot, "specs", "002-billing-reports"), { recursive: true });
		mkdirSync(path.join(repoRoot, "specs", "misc-not-a-feature"), { recursive: true });

		expect(listFeatureDirs(repoRoot)).toEqual(["001-auth-flow", "002-billing-reports"]);
		expect(resolveFeatureFromBranch(repoRoot, "002-any-branch-name")).toBe("002-billing-reports");
	});

	it("computes the next feature number from both specs and git branches", () => {
		const repoRoot = createTempDir("pi-spec-next-feature");
		mkdirSync(path.join(repoRoot, "specs", "002-billing-reports"), { recursive: true });
		mkdirSync(path.join(repoRoot, "specs", "005-data-import"), { recursive: true });

		expect(computeNextFeatureNumber(repoRoot, ["003-something", "origin/006-another"])).toBe(7);
	});

	it("finds the repo root from git first, then .specify fallback", () => {
		const repoRoot = createTempDir("pi-spec-root");
		mkdirSync(path.join(repoRoot, ".specify"), { recursive: true });
		const nested = path.join(repoRoot, "packages", "feature");
		mkdirSync(nested, { recursive: true });

		expect(findRepoRoot(nested, createGitMock()).repoRoot).toBe(repoRoot);

		const gitRoot = createTempDir("pi-spec-git-root");
		const gitNested = path.join(gitRoot, "nested");
		mkdirSync(gitNested, { recursive: true });
		const result = findRepoRoot(gitNested, createGitMock({ getRepoRoot: () => gitRoot }));
		expect(result).toEqual({ repoRoot: gitRoot, hasGit: true });
	});

	it("builds workflow paths for an active feature", () => {
		const repoRoot = "/repo";
		const paths = buildWorkflowPaths(repoRoot, "007-native-spec");
		expect(paths.featureSpec).toBe("/repo/specs/007-native-spec/spec.md");
		expect(paths.planFile).toBe("/repo/specs/007-native-spec/plan.md");
		expect(paths.constitutionFile).toBe("/repo/.specify/memory/constitution.md");
	});

	it("extracts feature numbers from numbered names", () => {
		expect(extractFeatureNumber("007-native-spec")).toBe(7);
		expect(extractFeatureNumber("main")).toBeNull();
	});
});

import { existsSync } from "node:fs";
import path from "node:path";
import { createGitClient, type GitClient } from "./git.js";
import { createJjClient } from "./jj.js";

export type VcsType = "jj" | "git";

export function detectVcsType(cwd: string): VcsType | null {
	let current = path.resolve(cwd);
	while (true) {
		if (existsSync(path.join(current, ".jj"))) {
			return "jj";
		}
		if (existsSync(path.join(current, ".git"))) {
			return "git";
		}
		const parent = path.dirname(current);
		if (parent === current) {
			return null;
		}
		current = parent;
	}
}

export function createVcsClient(cwd: string): GitClient {
	const type = detectVcsType(cwd);
	if (type === "jj") {
		return createJjClient();
	}
	return createGitClient();
}

