import { existsSync, statSync } from "node:fs";
import type { GitClient } from "./git.js";
import { readRegistry } from "./repo-registry.js";
import type { WorkspaceContext, WorkspaceResolvedPaths } from "./types.js";
import { findRepoRoot, findWorkspaceRoot } from "./workspace.js";

/**
 * Resolve the active repository context.
 *
 * Resolution strategy:
 * 1. Find workspace root (nearest ancestor with `.specify/`)
 * 2. Try to read the workspace registry (`.specify/workspace.json`)
 * 3. If registry exists → multi-repo mode:
 *    - If activeRepositoryId is set → use that repo's path as repoRoot
 *    - If no active repo and >1 registered → return context with null activeRepo (caller must guard)
 *    - If exactly 1 repo registered → auto-use it
 * 4. If no registry → single-repo mode: workspace root = repo root (current behavior)
 */
export function resolveActiveRepo(
	cwd: string,
	git: GitClient,
): WorkspaceContext {
	const workspaceRoot = findWorkspaceRoot(cwd);

	// No .specify/ found — pure single-repo fallback
	if (!workspaceRoot) {
		const { repoRoot } = findRepoRoot(cwd, git);
		return {
			workspaceRoot: repoRoot,
			repoRoot,
			registryPath: "",
			isMultiRepo: false,
			activeRepo: null,
			registry: null,
		};
	}

	// Try to read registry
	let registry;
	try {
		registry = readRegistry(workspaceRoot);
	} catch {
		// Invalid registry — fall back to single-repo
		const { repoRoot } = findRepoRoot(cwd, git);
		return {
			workspaceRoot,
			repoRoot,
			registryPath: "",
			isMultiRepo: false,
			activeRepo: null,
			registry: null,
		};
	}

	// No registry file → single-repo mode
	if (!registry) {
		const { repoRoot } = findRepoRoot(cwd, git);
		return {
			workspaceRoot,
			repoRoot,
			registryPath: "",
			isMultiRepo: false,
			activeRepo: null,
			registry: null,
		};
	}

	const { getRegistryPath } = require("./repo-registry.js") as typeof import("./repo-registry.js");
	const registryPath = getRegistryPath(workspaceRoot);

	// Multi-repo mode
	if (registry.repositories.length === 0) {
		return {
			workspaceRoot,
			repoRoot: workspaceRoot,
			registryPath,
			isMultiRepo: true,
			activeRepo: null,
			registry,
		};
	}

	// Single repo registered → auto-use it
	if (registry.repositories.length === 1) {
		const repo = registry.repositories[0];
		return {
			workspaceRoot,
			repoRoot: repo.path,
			registryPath,
			isMultiRepo: true,
			activeRepo: repo,
			registry,
		};
	}

	// Multiple repos — check for active selection
	if (registry.activeRepositoryId) {
		const activeRepo = registry.repositories.find((r) => r.id === registry.activeRepositoryId);
		if (activeRepo) {
			return {
				workspaceRoot,
				repoRoot: activeRepo.path,
				registryPath,
				isMultiRepo: true,
				activeRepo,
				registry,
			};
		}
	}

	// Multiple repos, no active selection → ambiguous
	return {
		workspaceRoot,
		repoRoot: workspaceRoot, // fallback, but callers should check activeRepo
		registryPath,
		isMultiRepo: true,
		activeRepo: null,
		registry,
	};
}

/**
 * Get resolved paths that split workspace-scoped paths from repo-scoped paths.
 */
export function getResolvedPaths(ctx: WorkspaceContext): WorkspaceResolvedPaths {
	const { join } = require("node:path") as typeof import("node:path");
	const specifyDir = join(ctx.workspaceRoot, ".specify");
	return {
		workspaceRoot: ctx.workspaceRoot,
		repoRoot: ctx.repoRoot,
		specifyDir,
		templatesDir: join(specifyDir, "templates"),
		memoryDir: join(specifyDir, "memory"),
		specsDir: join(ctx.repoRoot, "specs"),
	};
}

/**
 * Check if the workspace context requires an active repo selection before writes.
 * Returns true if writes should be blocked (ambiguous targeting).
 */
export function isAmbiguousTarget(ctx: WorkspaceContext): boolean {
	return ctx.isMultiRepo && ctx.activeRepo === null && (ctx.registry?.repositories.length ?? 0) > 1;
}

/**
 * Validate that the active repo path still exists and is a directory.
 */
export function isActiveRepoAvailable(ctx: WorkspaceContext): boolean {
	if (!ctx.activeRepo) {
		return false;
	}
	try {
		return existsSync(ctx.activeRepo.path) && statSync(ctx.activeRepo.path).isDirectory();
	} catch {
		return false;
	}
}

