import { mkdirSync, writeFileSync } from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, describe, expect, it } from "vitest";
import {
	addRepository,
	createEmptyRegistry,
	findRepoByNameOrId,
	getRegistryPath,
	isNestedPath,
	listRepositories,
	normalizeRepoPath,
	readRegistry,
	removeRepository,
	selectRepository,
	validateRegistry,
	writeRegistry,
} from "../extension/repo-registry.js";
import type { RepoRegistry } from "../extension/types.js";

const tempDirs: string[] = [];

function createTempDir(prefix: string): string {
	const dir = path.join(os.tmpdir(), `${prefix}-${Math.random().toString(36).slice(2, 8)}`);
	mkdirSync(dir, { recursive: true });
	tempDirs.push(dir);
	return dir;
}

function createWorkspace(): string {
	const ws = createTempDir("pi-spec-ws");
	mkdirSync(path.join(ws, ".specify"), { recursive: true });
	return ws;
}

function createRepo(name: string): string {
	const dir = createTempDir(`pi-spec-repo-${name}`);
	mkdirSync(path.join(dir, "specs"), { recursive: true });
	return dir;
}

function makeValidRegistry(repos: Array<{ name: string; path: string }> = []): RepoRegistry {
	const registry = createEmptyRegistry();
	for (const r of repos) {
		registry.repositories.push({
			id: `id-${r.name}`,
			name: r.name,
			path: r.path,
			createdAt: "2026-01-01T00:00:00.000Z",
			updatedAt: "2026-01-01T00:00:00.000Z",
			lastSelectedAt: null,
		});
	}
	return registry;
}

afterEach(async () => {
	const { rm } = await import("node:fs/promises");
	await Promise.all(tempDirs.map((dir) => rm(dir, { recursive: true, force: true })));
	tempDirs.length = 0;
});

// ── T007: Registry I/O tests ──────────────────────────────────────────────

describe("registry I/O", () => {
	it("reads a valid registry from disk", () => {
		const ws = createWorkspace();
		const registry = makeValidRegistry([{ name: "RepoA", path: "/tmp/repo-a" }]);
		writeFileSync(getRegistryPath(ws), JSON.stringify(registry), "utf8");

		const result = readRegistry(ws);
		expect(result).not.toBeNull();
		expect(result!.repositories).toHaveLength(1);
		expect(result!.repositories[0].name).toBe("RepoA");
	});

	it("returns null when registry file does not exist", () => {
		const ws = createWorkspace();
		expect(readRegistry(ws)).toBeNull();
	});

	it("round-trips write + read", () => {
		const ws = createWorkspace();
		const registry = makeValidRegistry([{ name: "Test", path: "/tmp/test" }]);
		writeRegistry(ws, registry);
		const result = readRegistry(ws);
		expect(result).toEqual(registry);
	});

	it("throws on invalid JSON in registry file", () => {
		const ws = createWorkspace();
		writeFileSync(getRegistryPath(ws), "not json", "utf8");
		expect(() => readRegistry(ws)).toThrow();
	});
});

describe("validateRegistry", () => {
	it("accepts a valid registry", () => {
		const registry = makeValidRegistry([{ name: "A", path: "/a" }]);
		expect(validateRegistry(registry)).toEqual([]);
	});

	it("rejects null", () => {
		expect(validateRegistry(null)).toContain("Registry must be a non-null object");
	});

	it("rejects missing version", () => {
		const errors = validateRegistry({ repositories: [] });
		expect(errors.some((e) => e.includes("version"))).toBe(true);
	});

	it("rejects duplicate names (case-insensitive)", () => {
		const registry = makeValidRegistry([
			{ name: "Alpha", path: "/a" },
			{ name: "alpha", path: "/b" },
		]);
		// Override IDs to be unique
		registry.repositories[0].id = "id-1";
		registry.repositories[1].id = "id-2";
		const errors = validateRegistry(registry);
		expect(errors.some((e) => e.includes("duplicate"))).toBe(true);
	});

	it("rejects activeRepositoryId pointing to unknown repo", () => {
		const registry = makeValidRegistry([{ name: "A", path: "/a" }]);
		registry.activeRepositoryId = "nonexistent-id";
		const errors = validateRegistry(registry);
		expect(errors.some((e) => e.includes("unknown repository"))).toBe(true);
	});
});

describe("normalizeRepoPath", () => {
	it("resolves relative paths to absolute", () => {
		const result = normalizeRepoPath("./relative/path");
		expect(path.isAbsolute(result)).toBe(true);
	});
});

describe("findRepoByNameOrId", () => {
	it("matches by exact ID first", () => {
		const registry = makeValidRegistry([{ name: "A", path: "/a" }]);
		const result = findRepoByNameOrId(registry, "id-A");
		expect(result?.matchType).toBe("id");
		expect(result?.repo.name).toBe("A");
	});

	it("matches by case-insensitive name", () => {
		const registry = makeValidRegistry([{ name: "MyRepo", path: "/a" }]);
		const result = findRepoByNameOrId(registry, "myrepo");
		expect(result?.matchType).toBe("name");
	});

	it("returns null when not found", () => {
		const registry = makeValidRegistry([{ name: "A", path: "/a" }]);
		expect(findRepoByNameOrId(registry, "nonexistent")).toBeNull();
	});
});

// ── T009: addRepository tests ─────────────────────────────────────────────

describe("addRepository", () => {
	it("adds first repo and auto-activates", () => {
		const ws = createWorkspace();
		const repo = createRepo("first");
		const { registry, added } = addRepository(ws, repo, "First");
		expect(added.name).toBe("First");
		expect(registry.activeRepositoryId).toBe(added.id);
		expect(registry.repositories).toHaveLength(1);
	});

	it("adds second repo without auto-activating", () => {
		const ws = createWorkspace();
		const repo1 = createRepo("one");
		const repo2 = createRepo("two");
		addRepository(ws, repo1, "One");
		const { registry } = addRepository(ws, repo2, "Two");
		expect(registry.repositories).toHaveLength(2);
		// Active should still be the first one
		expect(registry.activeRepositoryId).toBe(registry.repositories[0].id);
	});

	it("rejects duplicate name (case-insensitive)", () => {
		const ws = createWorkspace();
		const repo1 = createRepo("dup1");
		const repo2 = createRepo("dup2");
		addRepository(ws, repo1, "Same");
		expect(() => addRepository(ws, repo2, "same")).toThrow(/already exists/i);
	});

	it("rejects invalid path", () => {
		const ws = createWorkspace();
		expect(() => addRepository(ws, "/nonexistent/path/xyz", "Bad")).toThrow(/does not exist/i);
	});

	it("rejects duplicate path", () => {
		const ws = createWorkspace();
		const repo = createRepo("dup-path");
		addRepository(ws, repo, "First");
		expect(() => addRepository(ws, repo, "Second")).toThrow(/already registered/i);
	});
});

// ── T010: listRepositories tests ──────────────────────────────────────────

describe("listRepositories", () => {
	it("returns null when no registry exists", () => {
		const ws = createWorkspace();
		expect(listRepositories(ws)).toBeNull();
	});

	it("lists repos with availability and active indicator", () => {
		const ws = createWorkspace();
		const repo1 = createRepo("list1");
		const repo2 = createRepo("list2");
		addRepository(ws, repo1, "ListOne");
		addRepository(ws, repo2, "ListTwo");

		const result = listRepositories(ws);
		expect(result).not.toBeNull();
		expect(result!.entries).toHaveLength(2);
		expect(result!.entries[0].available).toBe(true);
		expect(result!.entries[0].isActive).toBe(true); // first auto-activated
		expect(result!.entries[1].isActive).toBe(false);
	});

	it("reports unavailable when path is missing", () => {
		const ws = createWorkspace();
		const repo = createRepo("available");
		addRepository(ws, repo, "Available");

		// Manually add a repo with a non-existent path
		const registry = readRegistry(ws)!;
		registry.repositories.push({
			id: "missing-id",
			name: "Missing",
			path: "/nonexistent/path/xyz",
			createdAt: "2026-01-01T00:00:00.000Z",
			updatedAt: "2026-01-01T00:00:00.000Z",
			lastSelectedAt: null,
		});
		writeRegistry(ws, registry);

		const result = listRepositories(ws);
		const missing = result!.entries.find((e) => e.repo.name === "Missing");
		expect(missing?.available).toBe(false);
	});
});

// ── T011: removeRepository tests ──────────────────────────────────────────

describe("removeRepository", () => {
	it("removes by name", () => {
		const ws = createWorkspace();
		const repo = createRepo("rem");
		addRepository(ws, repo, "ToRemove");
		const { removed } = removeRepository(ws, "ToRemove");
		expect(removed.name).toBe("ToRemove");
		expect(readRegistry(ws)!.repositories).toHaveLength(0);
	});

	it("removes by id", () => {
		const ws = createWorkspace();
		const repo = createRepo("rem-id");
		const { added } = addRepository(ws, repo, "ById");
		removeRepository(ws, added.id);
		expect(readRegistry(ws)!.repositories).toHaveLength(0);
	});

	it("clears activeRepositoryId when removing active repo", () => {
		const ws = createWorkspace();
		const repo = createRepo("active-rem");
		addRepository(ws, repo, "Active");
		const { wasActive } = removeRepository(ws, "Active");
		expect(wasActive).toBe(true);
		expect(readRegistry(ws)!.activeRepositoryId).toBeNull();
	});

	it("throws when repo not found", () => {
		const ws = createWorkspace();
		const repo = createRepo("exists");
		addRepository(ws, repo, "Exists");
		expect(() => removeRepository(ws, "Nonexistent")).toThrow(/No repository found/i);
	});
});

// ── T019: selectRepository tests ──────────────────────────────────────────

describe("selectRepository", () => {
	it("selects by name", () => {
		const ws = createWorkspace();
