import { mkdirSync, writeFileSync } from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, describe, expect, it } from "vitest";
import type { GitClient } from "../extension/git.js";
import { addRepository, getRegistryPath } from "../extension/repo-registry.js";
import {
	getResolvedPaths,
	isActiveRepoAvailable,
	isAmbiguousTarget,
	resolveActiveRepo,
} from "../extension/repo-resolver.js";
import type { RepoRegistry, WorkspaceContext } from "../extension/types.js";

const tempDirs: string[] = [];

function createTempDir(prefix: string): string {
	const dir = path.join(os.tmpdir(), `${prefix}-${Math.random().toString(36).slice(2, 8)}`);
	mkdirSync(dir, { recursive: true });
	tempDirs.push(dir);
	return dir;
}

function createWorkspace(): string {
	const ws = createTempDir("pi-spec-resolver-ws");
	mkdirSync(path.join(ws, ".specify"), { recursive: true });
	return ws;
}

function createRepo(name: string): string {
	const dir = createTempDir(`pi-spec-resolver-repo-${name}`);
	mkdirSync(path.join(dir, "specs"), { recursive: true });
	return dir;
}

function createGitMock(overrides: Partial<GitClient> = {}): GitClient {
	return {
		getRepoRoot: () => null,
		getCurrentBranch: () => null,
		listBranches: () => [],
		isDirty: () => false,
		createAndSwitchBranch: () => undefined,
		...overrides,
	};
}

afterEach(async () => {
	const { rm } = await import("node:fs/promises");
	await Promise.all(tempDirs.map((dir) => rm(dir, { recursive: true, force: true })));
	tempDirs.length = 0;
});

// ── T008: Resolver unit tests ─────────────────────────────────────────────

describe("resolveActiveRepo", () => {
	it("falls back to single-repo mode when no .specify/ exists", () => {
		const dir = createTempDir("no-specify");
		const git = createGitMock();
		const ctx = resolveActiveRepo(dir, git);
		expect(ctx.isMultiRepo).toBe(false);
		expect(ctx.registry).toBeNull();
		expect(ctx.repoRoot).toBe(path.resolve(dir));
	});

	it("falls back to single-repo mode when .specify/ exists but no registry", () => {
		const ws = createWorkspace();
		const git = createGitMock();
		// Run from inside workspace
		const ctx = resolveActiveRepo(ws, git);
		expect(ctx.isMultiRepo).toBe(false);
		expect(ctx.registry).toBeNull();
		expect(ctx.workspaceRoot).toBe(ws);
	});

	it("returns multi-repo context with active repo when registry has activeRepositoryId", () => {
		const ws = createWorkspace();
		const repo1 = createRepo("active");
		const repo2 = createRepo("other");
		addRepository(ws, repo1, "Active");
		addRepository(ws, repo2, "Other");
		// First repo is auto-activated
		const git = createGitMock();
		const ctx = resolveActiveRepo(ws, git);
		expect(ctx.isMultiRepo).toBe(true);
		expect(ctx.activeRepo).not.toBeNull();
		expect(ctx.activeRepo!.name).toBe("Active");
		expect(ctx.repoRoot).toBe(repo1);
	});

	it("returns ambiguous context when multiple repos and no active selection", () => {
		const ws = createWorkspace();
		const repo1 = createRepo("amb1");
		const repo2 = createRepo("amb2");
		addRepository(ws, repo1, "Amb1");
		addRepository(ws, repo2, "Amb2");
		// Clear active selection
		const registry: RepoRegistry = JSON.parse(
			require("node:fs").readFileSync(getRegistryPath(ws), "utf8"),
		);
		registry.activeRepositoryId = null;
		writeFileSync(getRegistryPath(ws), JSON.stringify(registry), "utf8");

		const git = createGitMock();
		const ctx = resolveActiveRepo(ws, git);
		expect(ctx.isMultiRepo).toBe(true);
		expect(ctx.activeRepo).toBeNull();
		expect(ctx.registry!.repositories).toHaveLength(2);
	});

	it("auto-uses single registered repo even without explicit active selection", () => {
		const ws = createWorkspace();
		const repo = createRepo("single");
		addRepository(ws, repo, "Single");
		// Clear active — but only 1 repo, so should auto-use
		const registry: RepoRegistry = JSON.parse(
			require("node:fs").readFileSync(getRegistryPath(ws), "utf8"),
		);
		registry.activeRepositoryId = null;
		writeFileSync(getRegistryPath(ws), JSON.stringify(registry), "utf8");

		const git = createGitMock();
		const ctx = resolveActiveRepo(ws, git);
		expect(ctx.isMultiRepo).toBe(true);
		expect(ctx.activeRepo).not.toBeNull();
		expect(ctx.activeRepo!.name).toBe("Single");
	});
});

