import { existsSync, readFileSync, statSync, writeFileSync } from "node:fs";
import { randomUUID } from "node:crypto";
import path from "node:path";
import type { RepoRegistry, RepoTarget } from "./types.js";

const REGISTRY_VERSION = "1.0";
const REGISTRY_FILENAME = "workspace.json";

/**
 * Get the expected registry file path for a workspace root.
 */
export function getRegistryPath(workspaceRoot: string): string {
	return path.join(workspaceRoot, ".specify", REGISTRY_FILENAME);
}

/**
 * Generate a stable, opaque repository ID using crypto.randomUUID().
 */
export function generateRepoId(): string {
	return randomUUID();
}

/**
 * Normalize and canonicalize a repository path to an absolute path.
 */
export function normalizeRepoPath(repoPath: string): string {
	return path.resolve(repoPath);
}

/**
 * Validate a registry object against the expected schema.
 * Returns an array of error messages (empty = valid).
 */
export function validateRegistry(data: unknown): string[] {
	const errors: string[] = [];
	if (data == null || typeof data !== "object") {
		return ["Registry must be a non-null object"];
	}

	const reg = data as Record<string, unknown>;

	if (typeof reg.version !== "string" || reg.version.length === 0) {
		errors.push("Registry 'version' must be a non-empty string");
	}

	if (!Array.isArray(reg.repositories)) {
		errors.push("Registry 'repositories' must be an array");
	} else {
		const names = new Set<string>();
		const paths = new Set<string>();
		for (let i = 0; i < reg.repositories.length; i++) {
			const repo = reg.repositories[i] as Record<string, unknown>;
			const prefix = `repositories[${i}]`;
			if (typeof repo.id !== "string" || repo.id.length === 0) {
				errors.push(`${prefix}.id must be a non-empty string`);
			}
			if (typeof repo.name !== "string" || repo.name.length === 0) {
				errors.push(`${prefix}.name must be a non-empty string`);
			} else {
				const lower = (repo.name as string).toLowerCase();
				if (names.has(lower)) {
					errors.push(`${prefix}.name '${repo.name}' is a duplicate (case-insensitive)`);
				}
				names.add(lower);
			}
			if (typeof repo.path !== "string" || repo.path.length === 0) {
				errors.push(`${prefix}.path must be a non-empty string`);
			} else {
				const normalized = normalizeRepoPath(repo.path as string);
				if (paths.has(normalized)) {
					errors.push(`${prefix}.path '${repo.path}' is a duplicate`);
				}
				paths.add(normalized);
			}
			if (typeof repo.createdAt !== "string" || repo.createdAt.length === 0) {
				errors.push(`${prefix}.createdAt must be a non-empty string`);
			}
			if (typeof repo.updatedAt !== "string" || repo.updatedAt.length === 0) {
				errors.push(`${prefix}.updatedAt must be a non-empty string`);
			}
		}
	}

	if (reg.activeRepositoryId !== null && reg.activeRepositoryId !== undefined) {
		if (typeof reg.activeRepositoryId !== "string" || (reg.activeRepositoryId as string).length === 0) {
			errors.push("Registry 'activeRepositoryId' must be a non-empty string or null");
		} else if (Array.isArray(reg.repositories)) {
			const repos = reg.repositories as Array<Record<string, unknown>>;
			const ids = new Set(repos.map((r) => r.id));
			if (!ids.has(reg.activeRepositoryId)) {
				errors.push(
					`Registry 'activeRepositoryId' references unknown repository '${reg.activeRepositoryId}'`,
				);
			}
		}
	}

	return errors;
}

/**
 * Read the registry from disk. Returns null if the file does not exist.
 * Throws if the file exists but is invalid.
 */
export function readRegistry(workspaceRoot: string): RepoRegistry | null {
	const registryPath = getRegistryPath(workspaceRoot);
	if (!existsSync(registryPath)) {
		return null;
	}

	const raw = readFileSync(registryPath, "utf8");
	const data = JSON.parse(raw) as unknown;
	const errors = validateRegistry(data);
	if (errors.length > 0) {
		throw new Error(`Invalid workspace registry at ${registryPath}:\n${errors.join("\n")}`);
	}

	return data as RepoRegistry;
}

/**
 * Write the registry to disk. Validates before writing.
 */
export function writeRegistry(workspaceRoot: string, registry: RepoRegistry): void {
	const errors = validateRegistry(registry);
	if (errors.length > 0) {
		throw new Error(`Cannot write invalid registry:\n${errors.join("\n")}`);
	}
	const registryPath = getRegistryPath(workspaceRoot);
	writeFileSync(registryPath, JSON.stringify(registry, null, 2) + "\n", "utf8");
}

/**
 * Create an empty registry with the current version.
 */
export function createEmptyRegistry(): RepoRegistry {
	return {
		version: REGISTRY_VERSION,
		repositories: [],
		activeRepositoryId: null,
	};
}

/**
 * Find a repository by name (case-insensitive) or by exact ID.
 * Returns the matching repo or null.
 */
export function findRepoByNameOrId(
	registry: RepoRegistry,
	nameOrId: string,
): { repo: RepoTarget; matchType: "id" | "name" } | null {
	// Exact ID match first
	const byId = registry.repositories.find((r) => r.id === nameOrId);
	if (byId) {
		return { repo: byId, matchType: "id" };
	}

	// Case-insensitive name match
	const lower = nameOrId.toLowerCase();
	const byName = registry.repositories.filter((r) => r.name.toLowerCase() === lower);
	if (byName.length === 1) {
		return { repo: byName[0], matchType: "name" };
	}

	return null;
}

/**
 * Check if a path is nested inside any registered repository or vice versa.
 */
export function isNestedPath(newPath: string, existingPaths: string[]): string | null {
	const normalized = normalizeRepoPath(newPath);
	for (const existing of existingPaths) {
		const normalizedExisting = normalizeRepoPath(existing);
		if (normalized.startsWith(normalizedExisting + path.sep) || normalized === normalizedExisting) {
			return normalizedExisting;
		}
		if (normalizedExisting.startsWith(normalized + path.sep)) {
			return normalizedExisting;
		}
	}
	return null;
}

/**
 * Add a repository to the registry.
 */
export function addRepository(
	workspaceRoot: string,
	repoPath: string,
	name: string,
): { registry: RepoRegistry; added: RepoTarget } {
	const normalizedPath = normalizeRepoPath(repoPath);

	// Validate path exists and is a directory
	if (!existsSync(normalizedPath)) {
		throw new Error(`Repository path does not exist: ${normalizedPath}`);
	}
	if (!statSync(normalizedPath).isDirectory()) {
		throw new Error(`Repository path is not a directory: ${normalizedPath}`);
	}

	// Read or create registry
	let registry = readRegistry(workspaceRoot);
	if (!registry) {
		registry = createEmptyRegistry();
	}

	// Check for duplicate name (case-insensitive)
	const lowerName = name.toLowerCase();
	if (registry.repositories.some((r) => r.name.toLowerCase() === lowerName)) {
		throw new Error(`A repository with name '${name}' already exists (names are case-insensitive)`);
	}

	// Check for duplicate path
	if (registry.repositories.some((r) => normalizeRepoPath(r.path) === normalizedPath)) {
		throw new Error(`A repository with path '${normalizedPath}' is already registered`);
	}

	// Check for nested paths
	const nested = isNestedPath(
		normalizedPath,
		registry.repositories.map((r) => r.path),
	);
	if (nested) {
		throw new Error(
			`Repository path '${normalizedPath}' is nested inside (or contains) already-registered repository '${nested}'`,
		);
	}

	const now = new Date().toISOString();
	const newRepo: RepoTarget = {
		id: generateRepoId(),
		name,
		path: normalizedPath,
		createdAt: now,
		updatedAt: now,
		lastSelectedAt: null,
	};

	registry.repositories.push(newRepo);

	// Auto-activate if this is the first repository
	if (registry.repositories.length === 1) {
		registry.activeRepositoryId = newRepo.id;
		newRepo.lastSelectedAt = now;
	}

	writeRegistry(workspaceRoot, registry);
	return { registry, added: newRepo };
}

/**
 * List repositories with availability info.
 */
export function listRepositories(workspaceRoot: string): {
	registry: RepoRegistry;
	entries: Array<{ repo: RepoTarget; available: boolean; isActive: boolean }>;
} | null {
	const registry = readRegistry(workspaceRoot);
	if (!registry) {
		return null;
	}

	const entries = registry.repositories.map((repo) => ({
		repo,
		available: existsSync(repo.path) && statSync(repo.path).isDirectory(),
		isActive: repo.id === registry.activeRepositoryId,
	}));

	return { registry, entries };
}

/**
 * Remove a repository by name or ID.
 */
export function removeRepository(
	workspaceRoot: string,
	nameOrId: string,
): { registry: RepoRegistry; removed: RepoTarget; wasActive: boolean } {
	const registry = readRegistry(workspaceRoot);
	if (!registry) {
		throw new Error("No workspace registry found. Run /spec repo add first.");
	}

	const match = findRepoByNameOrId(registry, nameOrId);
	if (!match) {
		throw new Error(`No repository found matching '${nameOrId}'`);
	}

	const wasActive = registry.activeRepositoryId === match.repo.id;
	registry.repositories = registry.repositories.filter((r) => r.id !== match.repo.id);

	if (wasActive) {
		registry.activeRepositoryId = null;
	}

	writeRegistry(workspaceRoot, registry);
	return { registry, removed: match.repo, wasActive };
}

/**
 * Select a repository as the active target.
 */
export function selectRepository(
	workspaceRoot: string,
	nameOrId: string,
): { registry: RepoRegistry; selected: RepoTarget } {
	const registry = readRegistry(workspaceRoot);
	if (!registry) {
		throw new Error("No workspace registry found. Run /spec repo add first.");
	}

	const match = findRepoByNameOrId(registry, nameOrId);
	if (!match) {
		throw new Error(`No repository found matching '${nameOrId}'`);
	}

	const now = new Date().toISOString();
	registry.activeRepositoryId = match.repo.id;
	match.repo.lastSelectedAt = now;
	match.repo.updatedAt = now;

	writeRegistry(workspaceRoot, registry);
	return { registry, selected: match.repo };
}

import { existsSync, statSync } from "node:fs";
import path from "node:path";
import type { GitClient } from "./git.js";
import { getRegistryPath, readRegistry } from "./repo-registry.js";
import type { WorkspaceContext, WorkspaceResolvedPaths } from "./types.js";
import { findRepoRoot, findWorkspaceRoot } from "./workspace.js";

/**
 * Resolve the active repository context.
 *
 * Resolution strategy:
 * 1. Find workspace root (nearest ancestor with `.specify/`)
 * 2. Try to read the workspace registry (`.specify/workspace.json`)
 * 3. If registry exists → multi-repo mode:
 *    - If activeRepositoryId is set → use that repo's path as repoRoot
 *    - If no active repo and >1 registered → return context with null activeRepo (caller must guard)
 *    - If exactly 1 repo registered → auto-use it
 * 4. If no registry → single-repo mode: workspace root = repo root (current behavior)
 */
export function resolveActiveRepo(
	cwd: string,
	git: GitClient,
): WorkspaceContext {
	const workspaceRoot = findWorkspaceRoot(cwd);

	// No .specify/ found — pure single-repo fallback
	if (!workspaceRoot) {
		const { repoRoot } = findRepoRoot(cwd, git);
		return {
			workspaceRoot: repoRoot,
			repoRoot,
			registryPath: "",
			isMultiRepo: false,
			activeRepo: null,
			registry: null,
		};
	}

	// Try to read registry
	let registry;
	try {
		registry = readRegistry(workspaceRoot);
	} catch {
		// Invalid registry — fall back to single-repo
		const { repoRoot } = findRepoRoot(cwd, git);
		return {
			workspaceRoot,
			repoRoot,
			registryPath: "",
			isMultiRepo: false,
			activeRepo: null,
			registry: null,
		};
	}

	// No registry file → single-repo mode
	if (!registry) {
		const { repoRoot } = findRepoRoot(cwd, git);
		return {
			workspaceRoot,
			repoRoot,
			registryPath: "",
			isMultiRepo: false,
			activeRepo: null,
			registry: null,
		};
	}

	const registryPath = getRegistryPath(workspaceRoot);

	// Multi-repo mode
	if (registry.repositories.length === 0) {
		return {
			workspaceRoot,
			repoRoot: workspaceRoot,
			registryPath,
			isMultiRepo: true,
			activeRepo: null,
			registry,
		};
	}

	// Single repo registered → auto-use it
	if (registry.repositories.length === 1) {
		const repo = registry.repositories[0];
		return {
			workspaceRoot,
			repoRoot: repo.path,
			registryPath,
			isMultiRepo: true,
			activeRepo: repo,
			registry,
		};
	}

	// Multiple repos — check for active selection
	if (registry.activeRepositoryId) {
		const activeRepo = registry.repositories.find((r) => r.id === registry.activeRepositoryId);
		if (activeRepo) {
			return {
				workspaceRoot,
				repoRoot: activeRepo.path,
				registryPath,
				isMultiRepo: true,
				activeRepo,
				registry,
			};
		}
	}

	// Multiple repos, no active selection → ambiguous
	return {
		workspaceRoot,
		repoRoot: workspaceRoot, // fallback, but callers should check activeRepo
		registryPath,
		isMultiRepo: true,
		activeRepo: null,
		registry,
	};
}

/**
 * Get resolved paths that split workspace-scoped paths from repo-scoped paths.
 */
export function getResolvedPaths(ctx: WorkspaceContext): WorkspaceResolvedPaths {
	const specifyDir = path.join(ctx.workspaceRoot, ".specify");
	return {
		workspaceRoot: ctx.workspaceRoot,
		repoRoot: ctx.repoRoot,
		specifyDir,
		templatesDir: path.join(specifyDir, "templates"),
		memoryDir: path.join(specifyDir, "memory"),
		specsDir: path.join(ctx.repoRoot, "specs"),
	};
}

/**
 * Check if the workspace context requires an active repo selection before writes.
 * Returns true if writes should be blocked (ambiguous targeting).
 */
export function isAmbiguousTarget(ctx: WorkspaceContext): boolean {
	return ctx.isMultiRepo && ctx.activeRepo === null && (ctx.registry?.repositories.length ?? 0) > 1;
}

/**
 * Validate that the active repo path still exists and is a directory.
 */
export function isActiveRepoAvailable(ctx: WorkspaceContext): boolean {
	if (!ctx.activeRepo) {
		return false;
	}
	try {
		return existsSync(ctx.activeRepo.path) && statSync(ctx.activeRepo.path).isDirectory();
	} catch {
		return false;
	}
}

import type { ExtensionAPI, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import { Text } from "@mariozechner/pi-tui";
import { getStatus, syncFeature, syncTasks } from "./linear.js";
import {
	addRepository,
	listRepositories,
	removeRepository,
	selectRepository,
} from "./repo-registry.js";
import { isAmbiguousTarget, resolveActiveRepo } from "./repo-resolver.js";
import { createVcsClient } from "./vcs.js";
import { buildWorkflowPrompt, getStepNotes } from "./prompts.js";
import {
	ensureFeatureArtifacts,
	ensurePlanArtifact,
	ensureWorkflowScaffold,
	formatCreatedFiles,
	getWorkflowTemplatePath,
} from "./scaffold.js";
import {
	buildWorkflowStatus,
	formatFeatureList,
	formatHelpReport,
	formatRepoList,
	formatRepoStatus,
	formatWorkflowStatus,
	summarizeChecklists,
} from "./status.js";
import { SPEC_SUBCOMMANDS, type SpecSubcommand, type WorkspaceContext, type WorkflowPaths, type WorkflowStep } from "./types.js";
import {
	buildWorkflowPaths,
	findRepoRoot,
	getLatestFeatureDir,
	listFeatureDirs,
	prepareFeatureWorkspace,
	resolveFeatureFromBranch,
} from "./workspace.js";

const REPORT_MESSAGE_TYPE = "pi-spec-report";
const PROMPT_OPTIONAL_STEPS = new Set<WorkflowStep>(["clarify", "tasks", "analyze", "implement"]);

function tokenize(input: string): { subcommand: SpecSubcommand | null; remainder: string } {
	const trimmed = input.trim();
	if (!trimmed) {
		return { subcommand: "status", remainder: "" };
	}
	const [raw, ...rest] = trimmed.split(/\s+/);
	const normalized = raw.toLowerCase();
	if ((SPEC_SUBCOMMANDS as readonly string[]).includes(normalized)) {
		return { subcommand: normalized as SpecSubcommand, remainder: rest.join(" ").trim() };
	}
	return { subcommand: null, remainder: trimmed };
}

function sendReport(pi: ExtensionAPI, content: string): void {
	pi.sendMessage({ customType: REPORT_MESSAGE_TYPE, content, display: true });
}

function isWorkflowStep(subcommand: SpecSubcommand): subcommand is WorkflowStep {
	return ["constitution", "specify", "clarify", "checklist", "plan", "tasks", "analyze", "implement"].includes(
		subcommand,
	);
}

async function promptForMissingInput(
	ctx: ExtensionCommandContext,
	title: string,
	placeholder: string,
): Promise<string | undefined> {
	if (!ctx.hasUI) {
		return undefined;
	}
	if (typeof ctx.ui.editor === "function") {
		const response = await ctx.ui.editor(title, placeholder);
		return response?.trim() || undefined;
	}
	if (typeof ctx.ui.input === "function") {
		const response = await ctx.ui.input(title, placeholder);
		return response?.trim() || undefined;
	}
	return undefined;
}

function stepNeedsRequiredInput(step: WorkflowStep): boolean {
	return !PROMPT_OPTIONAL_STEPS.has(step);
}

async function resolveActiveFeatureName(
	ctx: ExtensionCommandContext,
	repoRoot: string,
	currentBranch: string,
	hasGit = true,
): Promise<string | undefined> {
	const featureFromBranch = resolveFeatureFromBranch(repoRoot, currentBranch);
	if (featureFromBranch) {
		return featureFromBranch;
	}

	// When git is available, the current branch is the source of truth for the
	// active feature — matching upstream spec-kit behavior.  The specs/ directory
	// scan is only a fallback for non-git repositories where branch detection is
	// unavailable.
	if (hasGit) {
		return undefined;
	}

	const features = listFeatureDirs(repoRoot);
	if (features.length === 0) {
		return undefined;
	}
	if (features.length === 1) {
		return features[0];
	}
	if (!ctx.hasUI || typeof ctx.ui.select !== "function") {
		return getLatestFeatureDir(repoRoot);
	}
	const selected = await ctx.ui.select("Select active spec feature", features);
	return selected || undefined;
}

async function resolveFeaturePaths(
	ctx: ExtensionCommandContext,
	repoRoot: string,
	currentBranch: string,
	hasGit = true,
	workspaceRoot?: string,
): Promise<WorkflowPaths | undefined> {
	const featureName = await resolveActiveFeatureName(ctx, repoRoot, currentBranch, hasGit);
	if (!featureName) {
		ctx.ui.notify("No active feature found. Run /spec specify <feature description> first.", "warning");
		return undefined;
	}
	return buildWorkflowPaths(repoRoot, featureName, workspaceRoot);
}

function queueWorkflow(
	pi: ExtensionAPI,
	step: WorkflowStep,
	currentBranch: string,
	paths: WorkflowPaths,
	input: string,
): void {
	const prompt = buildWorkflowPrompt({
		step,
		input,
		paths,
		currentBranch,
		workflowTemplatePath: getWorkflowTemplatePath(paths, step),
		stepNotes: getStepNotes(step),
		checklists: step === "implement" ? summarizeChecklists(paths.checklistsDir) : undefined,
	});
	pi.sendUserMessage(prompt);
}

async function collectStepInput(ctx: ExtensionCommandContext, step: WorkflowStep, existing: string): Promise<string> {
	if (existing.trim() || !stepNeedsRequiredInput(step)) {
		return existing.trim();
	}

	const titleByStep: Record<WorkflowStep, string> = {
		constitution: "Describe the constitution principles",
		specify: "Describe the feature to specify",
		clarify: "Optional clarification focus",
		checklist: "Optional checklist focus or domain",
		plan: "Describe the technical context",
		tasks: "Optional task-generation context",
		analyze: "Optional analysis focus",
		implement: "Optional implementation focus",
	};

	return (
		(await promptForMissingInput(ctx, titleByStep[step], "Write the details for this /spec step here")) ?? ""
	).trim();
}

function makeEnv(ctx: ExtensionCommandContext, git = createVcsClient(ctx.cwd)) {
	const wsCtx = resolveActiveRepo(ctx.cwd, git);
	const repoRoot = wsCtx.repoRoot;
	const { hasGit } = findRepoRoot(ctx.cwd, git);
	const currentBranch = git.getCurrentBranch(repoRoot) ?? process.env.SPECIFY_FEATURE ?? "main";
	const basePaths = buildWorkflowPaths(repoRoot, undefined, wsCtx.workspaceRoot);
	return { git, repoRoot, hasGit, currentBranch, basePaths, wsCtx };
}

function handleInit(pi: ExtensionAPI, repoRoot: string, created: string[]): void {
	sendReport(
		pi,
		[
			"# /spec init",
			"",
			`- Repository root: ${repoRoot}`,
			formatCreatedFiles(created),
			"",
			"Next: `/spec constitution <principles>` or `/spec specify <feature description>`.",
		].join("\n"),
	);
}

async function handleStatus(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
): Promise<void> {
	const activeFeature = await resolveActiveFeatureName(ctx, env.repoRoot, env.currentBranch, env.hasGit);
	sendReport(
		pi,
		formatWorkflowStatus(
			buildWorkflowStatus({
				repoRoot: env.repoRoot,
				currentBranch: env.currentBranch,
				paths: buildWorkflowPaths(env.repoRoot, activeFeature, env.wsCtx.workspaceRoot),
				activeFeature,
				wsCtx: env.wsCtx,
			}),
			env.wsCtx,
		),
	);
}

async function handleNext(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
): Promise<void> {
	const activeFeature = await resolveActiveFeatureName(ctx, env.repoRoot, env.currentBranch, env.hasGit);
	const status = buildWorkflowStatus({
		repoRoot: env.repoRoot,
		currentBranch: env.currentBranch,
		paths: buildWorkflowPaths(env.repoRoot, activeFeature, env.wsCtx.workspaceRoot),
		activeFeature,
		wsCtx: env.wsCtx,
	});
	sendReport(pi, `# Next /spec steps\n\n${status.nextSteps.map((step) => `- ${step}`).join("\n")}`);
}

function handleSpecify(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
	input: string,
): void {
	if (!input) {
		ctx.ui.notify("/spec specify requires a feature description.", "warning");
		return;
	}

	try {
		const prepared = prepareFeatureWorkspace({
			repoRoot: env.repoRoot,
			description: input,
			git: env.git,
			currentBranch: env.currentBranch,
			hasGit: env.hasGit,
		});
		const paths = buildWorkflowPaths(env.repoRoot, prepared.branchName, env.wsCtx.workspaceRoot);
		ensureWorkflowScaffold(paths);
		ensureFeatureArtifacts(paths);
		queueWorkflow(pi, "specify", prepared.branchName, paths, input);
		sendReport(
			pi,
			[
				"# /spec specify",
				"",
				`- Feature branch: ${prepared.branchName}`,
				`- Feature number: ${prepared.featureNumber}`,
				`- Feature directory: ${prepared.featureDir}`,
				`- Spec file: ${prepared.specFile}`,
				env.wsCtx.isMultiRepo ? `- Active repository: ${env.wsCtx.activeRepo?.name ?? "(none)"}` : "",
				"",
				"Queued the native specification workflow as a user message.",
			].filter(Boolean).join("\n"),
		);
	} catch (error) {
		ctx.ui.notify(
			`Failed to prepare feature workspace: ${error instanceof Error ? error.message : String(error)}`,
			"error",
		);
	}
}

async function confirmChecklistOverride(ctx: ExtensionCommandContext, paths: WorkflowPaths): Promise<boolean> {
	const checklists = summarizeChecklists(paths.checklistsDir);
	if (
		!(checklists.some((checklist) => checklist.incomplete > 0) && ctx.hasUI && typeof ctx.ui.confirm === "function")
	) {
		return true;
	}

	const proceed = await ctx.ui.confirm(
		"Incomplete spec checklists",
		`${checklists.map((checklist) => `${checklist.name}: ${checklist.incomplete} incomplete item(s)`).join("\n")}

Proceed with implementation anyway?`,
	);
	if (!proceed) {
		ctx.ui.notify("Implementation cancelled until the checklist review is complete.", "info");
	}
	return proceed;
}

async function handleWorkflowStep(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
	step: WorkflowStep,
	input: string,
): Promise<void> {
	if (step === "specify") {
		handleSpecify(pi, ctx, env, input);
		return;
	}

	const featurePaths =
		step === "constitution"
			? buildWorkflowPaths(
					env.repoRoot,
					await resolveActiveFeatureName(ctx, env.repoRoot, env.currentBranch, env.hasGit),
					env.wsCtx.workspaceRoot,
				)
			: await resolveFeaturePaths(ctx, env.repoRoot, env.currentBranch, env.hasGit, env.wsCtx.workspaceRoot);
	ensureWorkflowScaffold(featurePaths ?? env.basePaths);
	if (!featurePaths) {
		return;
	}

	if (step === "plan") {
		ensurePlanArtifact(featurePaths);
	}
	if (step === "implement" && !(await confirmChecklistOverride(ctx, featurePaths))) {
		return;
	}

	queueWorkflow(pi, step, env.currentBranch, featurePaths, input);
	ctx.ui.notify(`Queued /spec ${step} workflow.`, "info");
}

// ── Repo management handlers ──────────────────────────────────────────────

const REPO_SUBCOMMANDS = ["add", "list", "use", "remove", "status"] as const;
type RepoSubcommand = (typeof REPO_SUBCOMMANDS)[number];

function tokenizeRepoArgs(input: string): { sub: RepoSubcommand | null; remainder: string } {
	const trimmed = input.trim();
	if (!trimmed) {
		return { sub: "status", remainder: "" };
	}
	const [raw, ...rest] = trimmed.split(/\s+/);
	const normalized = raw.toLowerCase();
	if ((REPO_SUBCOMMANDS as readonly string[]).includes(normalized)) {
		return { sub: normalized as RepoSubcommand, remainder: rest.join(" ").trim() };
	}
	return { sub: null, remainder: trimmed };
}

async function handleRepoAdd(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
	args: string,
): Promise<void> {
	// Parse: /spec repo add <path> [name]
	const parts = args.trim().split(/\s+/);
	const repoPath = parts[0];
	let name = parts.slice(1).join(" ").trim();

	if (!repoPath) {
		ctx.ui.notify("/spec repo add requires a path. Usage: /spec repo add <path> [name]", "warning");
		return;
	}

	if (!name && ctx.hasUI && typeof ctx.ui.input === "function") {
		const prompted = await ctx.ui.input("Repository name", "Enter a friendly name for this repository");
		name = prompted?.trim() ?? "";
	}

	if (!name) {
		// Derive name from directory basename
		const { basename } = await import("node:path");
		name = basename(repoPath);
	}

	try {
		const { added } = addRepository(env.wsCtx.workspaceRoot, repoPath, name);
		sendReport(pi, [
			"# /spec repo add",
			"",
			`- Name: ${added.name}`,
			`- Path: ${added.path}`,
			`- ID: ${added.id}`,
			added.lastSelectedAt ? "- Auto-activated as the only registered repository" : "",
			"",
			"Next: `/spec repo list` to see all repositories, or `/spec repo use <name>` to switch.",
		].filter(Boolean).join("\n"));
	} catch (error) {
		ctx.ui.notify(
			`Failed to add repository: ${error instanceof Error ? error.message : String(error)}`,
			"error",
		);
	}
}

function handleRepoList(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
): void {
	const result = listRepositories(env.wsCtx.workspaceRoot);
	if (!result || result.entries.length === 0) {
		sendReport(pi, "# /spec repo list\n\nNo repositories registered. Run `/spec repo add <path> [name]` first.");
		return;
	}
	sendReport(pi, formatRepoList(result.entries));
}

async function handleRepoRemove(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
	nameOrId: string,
): Promise<void> {
	if (!nameOrId) {
		ctx.ui.notify("/spec repo remove requires a name or ID. Usage: /spec repo remove <name|id>", "warning");
		return;
	}

	if (ctx.hasUI && typeof ctx.ui.confirm === "function") {
		const proceed = await ctx.ui.confirm(
			"Remove repository",
			`Remove '${nameOrId}' from the workspace registry? This does not delete any files on disk.`,
		);
		if (!proceed) {
			ctx.ui.notify("Repository removal cancelled.", "info");
			return;
		}
	}

	try {
		const { removed, wasActive } = removeRepository(env.wsCtx.workspaceRoot, nameOrId);
		sendReport(pi, [
			"# /spec repo remove",
			"",
			`- Removed: ${removed.name} (${removed.path})`,
			wasActive ? "- ⚠️ This was the active repository. No active repository is now selected." : "",
			wasActive ? "- Run `/spec repo use <name>` to select a new active repository." : "",
		].filter(Boolean).join("\n"));
	} catch (error) {
		ctx.ui.notify(
			`Failed to remove repository: ${error instanceof Error ? error.message : String(error)}`,
			"error",
		);
	}
}

async function handleRepoUse(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
	nameOrId: string,
): Promise<void> {
	if (!nameOrId) {
		ctx.ui.notify("/spec repo use requires a name or ID. Usage: /spec repo use <name|id>", "warning");
		return;
	}

	try {
		const { selected } = selectRepository(env.wsCtx.workspaceRoot, nameOrId);
		sendReport(pi, [
			"# /spec repo use",
			"",
			`- Active repository: ${selected.name}`,
			`- Path: ${selected.path}`,
			"",
			"All `/spec` commands will now target this repository.",
		].join("\n"));
	} catch (error) {
		ctx.ui.notify(
			`Failed to select repository: ${error instanceof Error ? error.message : String(error)}`,
			"error",
		);
	}
}

function handleRepoStatus(
	pi: ExtensionAPI,
	env: ReturnType<typeof makeEnv>,
): void {
	const result = listRepositories(env.wsCtx.workspaceRoot);
	sendReport(pi, formatRepoStatus(env.wsCtx, result?.entries ?? []));
}

async function handleRepo(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
	remainder: string,
): Promise<void> {
	const { sub, remainder: args } = tokenizeRepoArgs(remainder);

	switch (sub) {
		case "add":
			await handleRepoAdd(pi, ctx, env, args);
			return;
		case "list":
			handleRepoList(pi, ctx, env);
			return;
		case "use":
			await handleRepoUse(pi, ctx, env, args);
			return;
		case "remove":
			await handleRepoRemove(pi, ctx, env, args);
			return;
		case "status":
			handleRepoStatus(pi, env);
			return;
		default:
			ctx.ui.notify(
				`Unknown /spec repo subcommand: ${remainder}\nAvailable: add, list, use, remove, status`,
				"warning",
			);
	}
}

async function handleLinear(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
	linearSubcommand: string,
): Promise<void> {
	// Parse linear subcommand (sync-feature, sync-tasks, status)
	const normalized = linearSubcommand.toLowerCase().trim();

	// Resolve active feature
	const featurePaths = await resolveFeaturePaths(ctx, env.repoRoot, env.currentBranch, env.hasGit);
	if (!featurePaths) {
		return;
	}

	try {
		if (normalized === "sync-feature") {
			await syncFeature(ctx, featurePaths, pi);
		} else if (normalized === "sync-tasks") {
			await syncTasks(ctx, featurePaths, pi);
		} else if (normalized === "status") {
			await getStatus(ctx, featurePaths, pi);
		} else {
			ctx.ui.notify(
				`Unknown /spec linear subcommand: ${linearSubcommand}\n` +
					"Available: sync-feature, sync-tasks, status",
				"warning",
			);
		}
	} catch (error) {
		const message = error instanceof Error ? error.message : String(error);
		ctx.ui.notify(`Linear operation failed: ${message}`, "error");
	}
}

export default function specExtension(pi: ExtensionAPI) {
	pi.registerMessageRenderer(REPORT_MESSAGE_TYPE, (message, _options, theme) => {
		const text = `${theme.fg("accent", theme.bold("spec"))}\n\n${String(message.content ?? "")}`;
		return new Text(text, 0, 0);
	});

	pi.registerCommand("spec", {
		description:
			"Native spec-kit workflow for pi (/spec init|constitution|specify|clarify|checklist|plan|tasks|analyze|implement)",
		getArgumentCompletions(prefix) {
			const trimmed = prefix.trimStart();
			const parts = trimmed.split(/\s+/);

			// Complete second-level subcommands for "/spec repo ..."
			if (parts.length === 2 && parts[0].toLowerCase() === "repo") {
				const sub = parts[1];
				const values = REPO_SUBCOMMANDS.filter((cmd) => cmd.startsWith(sub.toLowerCase())).map((cmd) => ({
					value: `repo ${cmd}`,
					label: `repo ${cmd}`,
				}));
				return values.length > 0 ? values : null;
			}

			// Complete first-level subcommands
			if (!trimmed.includes(" ")) {
				const values = SPEC_SUBCOMMANDS.filter((command) => command.startsWith(trimmed)).map((command) => ({
					value: command,
					label: command,
				}));
				return values.length > 0 ? values : null;
			}

			return null;
		},
		handler: async (rawArgs, ctx) => {
			const { subcommand, remainder } = tokenize(rawArgs);
			if (!subcommand) {
				ctx.ui.notify(`Unknown /spec subcommand: ${rawArgs.trim()}`, "warning");
				sendReport(pi, formatHelpReport());
				return;
			}

			const env = makeEnv(ctx);
			if (subcommand === "init") {
				handleInit(pi, env.repoRoot, ensureWorkflowScaffold(env.basePaths));
				return;
			}
			if (subcommand === "help") {
				sendReport(pi, formatHelpReport());
				return;
			}
			if (subcommand === "list") {
				sendReport(pi, formatFeatureList(env.repoRoot));
				return;
			}
			if (subcommand === "status") {
				await handleStatus(pi, ctx, env);
				return;
			}
			if (subcommand === "next") {
				await handleNext(pi, ctx, env);
				return;
			}
			if (subcommand === "linear") {
				await handleLinear(pi, ctx, env, remainder);
				return;
			}
			if (subcommand === "repo") {
				await handleRepo(pi, ctx, env, remainder);
				return;
			}
			if (!isWorkflowStep(subcommand)) {
				sendReport(pi, formatHelpReport());
				return;
			}

			// Write-safety guard: block write-capable steps when multi-repo targeting is ambiguous
			if (isAmbiguousTarget(env.wsCtx)) {
				const repoNames = env.wsCtx.registry?.repositories.map((r) => r.name).join(", ") ?? "";
				ctx.ui.notify(
					`Multiple repositories registered (${repoNames}) but no active repository selected.\n` +
						"Run `/spec repo use <name>` to select a target before running workflow commands.",
					"warning",
				);
				return;
			}

			const input = await collectStepInput(ctx, subcommand, remainder);
			await handleWorkflowStep(pi, ctx, env, subcommand, input);
		},
	});
}

import { existsSync, readdirSync, readFileSync, statSync } from "node:fs";
import path from "node:path";
import type { ChecklistSummary, RepoTarget, WorkflowPaths, WorkflowStatus, WorkspaceContext } from "./types.js";
import { getLatestFeatureDir, listFeatureDirs } from "./workspace.js";

function countChecklistItems(content: string): { total: number; completed: number; incomplete: number } {
	const lines = content.split(/\r?\n/);
	let total = 0;
	let completed = 0;
	let incomplete = 0;
	for (const line of lines) {
		if (/^- \[(?: |x|X)\]/.test(line)) {
			total++;
			if (/^- \[(?:x|X)\]/.test(line)) {
				completed++;
			} else {
				incomplete++;
			}
		}
	}
	return { total, completed, incomplete };
}

export function summarizeChecklists(checklistsDir?: string): ChecklistSummary[] {
	if (!(checklistsDir && existsSync(checklistsDir))) {
		return [];
	}

	return readdirSync(checklistsDir)
		.filter((entry) => entry.endsWith(".md"))
		.map((entry) => {
			const fullPath = path.join(checklistsDir, entry);
			const content = readFileSync(fullPath, "utf8");
			const counts = countChecklistItems(content);
			return {
				name: entry,
				path: fullPath,
				...counts,
				status: counts.incomplete === 0 ? "pass" : "fail",
			} satisfies ChecklistSummary;
		})
		.sort((a, b) => a.name.localeCompare(b.name));
}

function nextStepsFor(paths: WorkflowPaths, initialized: boolean): string[] {
	if (!initialized) {
		return ["/spec init", "/spec constitution <principles>", "/spec specify <feature description>"];
	}

	if (!(paths.featureDir && paths.featureSpec)) {
		return ["/spec specify <feature description>", "/spec list"];
	}

	const steps: string[] = [];
	const specExists = existsSync(paths.featureSpec);
	const planExists = !!paths.planFile && existsSync(paths.planFile);
	const tasksExist = !!paths.tasksFile && existsSync(paths.tasksFile);
	const checklists = summarizeChecklists(paths.checklistsDir);
	const hasIncompleteChecklist = checklists.some((checklist) => checklist.incomplete > 0);

	if (!specExists) {
		steps.push("/spec specify <feature description>");
		return steps;
	}

	steps.push("/spec clarify");
	steps.push("/spec checklist quality");

	if (!planExists) {
		steps.push("/spec plan <technical context>");
		return steps;
	}

	if (!tasksExist) {
		steps.push("/spec tasks");
		return steps;
	}

	steps.push("/spec analyze");
	steps.push(hasIncompleteChecklist ? "/spec implement (after checklist review)" : "/spec implement");
	return steps;
}

export function buildWorkflowStatus(options: {
	repoRoot: string;
	currentBranch: string;
	paths: WorkflowPaths;
	activeFeature?: string;
	wsCtx?: WorkspaceContext;
}): WorkflowStatus {
	const featureDirs = listFeatureDirs(options.repoRoot);
	const activeFeature = options.activeFeature ?? getLatestFeatureDir(options.repoRoot);
	const initialized = existsSync(options.paths.specifyDir);
	const artifacts = [
		{
			label: ".specify/README.md",
			path: options.paths.workflowReadmeFile,
			exists: existsSync(options.paths.workflowReadmeFile),
		},
		{
			label: "constitution.md",
			path: options.paths.constitutionFile,
			exists: existsSync(options.paths.constitutionFile),
		},
		{ label: "pi-agent.md", path: options.paths.agentContextFile, exists: existsSync(options.paths.agentContextFile) },
		{
			label: "extensions.yml",
			path: options.paths.extensionsConfigFile,
			exists: existsSync(options.paths.extensionsConfigFile),
		},
	];

	if (options.paths.featureSpec) {
		artifacts.push({
			label: "spec.md",
			path: options.paths.featureSpec,
			exists: existsSync(options.paths.featureSpec),
		});
	}
	if (options.paths.planFile) {
		artifacts.push({ label: "plan.md", path: options.paths.planFile, exists: existsSync(options.paths.planFile) });
	}
	if (options.paths.tasksFile) {
		artifacts.push({ label: "tasks.md", path: options.paths.tasksFile, exists: existsSync(options.paths.tasksFile) });
	}
	if (options.paths.researchFile) {
		artifacts.push({
			label: "research.md",
			path: options.paths.researchFile,
			exists: existsSync(options.paths.researchFile),
		});
	}
	if (options.paths.dataModelFile) {
		artifacts.push({
			label: "data-model.md",
			path: options.paths.dataModelFile,
			exists: existsSync(options.paths.dataModelFile),
		});
	}
	if (options.paths.quickstartFile) {
		artifacts.push({
			label: "quickstart.md",
			path: options.paths.quickstartFile,
			exists: existsSync(options.paths.quickstartFile),
		});
	}
	if (options.paths.contractsDir) {
		artifacts.push({
			label: "contracts/",
			path: options.paths.contractsDir,
			exists: existsSync(options.paths.contractsDir) && statSync(options.paths.contractsDir).isDirectory(),
		});
	}

	return {
		initialized,
		repoRoot: options.repoRoot,
		currentBranch: options.currentBranch,
		featureDirs,
		activeFeature,
		paths: options.paths,
		artifacts,
		checklists: summarizeChecklists(options.paths.checklistsDir),
		nextSteps: nextStepsFor(options.paths, initialized),
	};
}

export function formatWorkflowStatus(status: WorkflowStatus, wsCtx?: WorkspaceContext): string {
	const lines = [
		"# /spec workflow status",
		"",
		`- Repository root: ${status.repoRoot}`,
	];

	if (wsCtx?.isMultiRepo) {
		lines.push(`- Workspace root: ${wsCtx.workspaceRoot}`);
		lines.push(`- Active repository: ${wsCtx.activeRepo ? `${wsCtx.activeRepo.name} (${wsCtx.activeRepo.path})` : "(none)"}`);
	}

	lines.push(
		`- Initialized: ${status.initialized ? "yes" : "no"}`,
		`- Current branch: ${status.currentBranch}`,
		`- Active feature: ${status.activeFeature ?? "(none)"}`,
		`- Known features: ${status.featureDirs.length > 0 ? status.featureDirs.join(", ") : "(none)"}`,
		"",
		"## Artifacts",
	);

	for (const artifact of status.artifacts) {
		lines.push(`- ${artifact.exists ? "[x]" : "[ ]"} ${artifact.label} — ${artifact.path}`);
	}

	lines.push("", "## Checklist status");
	if (status.checklists.length === 0) {
		lines.push("- No checklist files found.");
	} else {
		for (const checklist of status.checklists) {
			lines.push(
				`- ${checklist.status === "pass" ? "[ok]" : "[!]"} ${checklist.name}: ${checklist.completed}/${checklist.total} complete (${checklist.incomplete} incomplete)`,
			);
		}
	}

	lines.push("", "## Next steps");
	for (const step of status.nextSteps) {
		lines.push(`- ${step}`);
	}
	return lines.join("\n");
}

export function formatHelpReport(): string {
	return [
		"# Native /spec workflow",
		"",
		"Use `/spec` with one of these subcommands:",
		"",
		"- `/spec init` — scaffold `.specify/`, templates, and memory files",
		"- `/spec constitution <principles>` — create or amend the project constitution",
		"- `/spec specify <feature description>` — create a numbered feature branch and spec scaffold",
		"- `/spec clarify [focus]` — resolve critical ambiguities in the active spec",
		"- `/spec checklist [domain]` — generate a requirements-quality checklist",
		"- `/spec plan <technical context>` — build the implementation plan and design artifacts",
		"- `/spec tasks [context]` — derive an executable tasks.md ordered by user story",
		"- `/spec analyze [focus]` — run a read-only cross-artifact consistency review",
		"- `/spec implement [focus]` — execute the plan from tasks.md and mark completed tasks",
		"- `/spec status` — show current workflow state",
		"- `/spec next` — show the next recommended command",
		"- `/spec list` — list all known feature directories",
		"",
		"**Multi-repo management:**",
		"",
		"- `/spec repo add <path> [name]` — register a repository target",
		"- `/spec repo list` — list registered repositories",
		"- `/spec repo use <name|id>` — select the active repository",
		"- `/spec repo remove <name|id>` — unregister a repository",
		"- `/spec repo status` — show repository registry state",
		"",
		"Tip: `/spec` with no arguments shows the current workflow status.",
	].join("\n");
}

export function formatFeatureList(repoRoot: string): string {
	const features = listFeatureDirs(repoRoot);
	if (features.length === 0) {
		return "# Known features\n\n- No feature directories found yet.";
	}
	return `# Known features\n\n${features.map((feature) => `- ${feature}`).join("\n")}`;
}

// ── Multi-repo formatting ─────────────────────────────────────────────────

export function formatRepoList(
	entries: Array<{ repo: RepoTarget; available: boolean; isActive: boolean }>,
): string {
	const lines = [
		"# /spec repo list",
		"",
	];

	for (const entry of entries) {
		const active = entry.isActive ? " ← active" : "";
		const status = entry.available ? "" : " [unavailable]";
		lines.push(`- **${entry.repo.name}**${active}${status}`);
		lines.push(`  Path: ${entry.repo.path}`);
		lines.push(`  ID: ${entry.repo.id.slice(0, 8)}...`);
	}

	return lines.join("\n");
}

export function formatRepoStatus(
	wsCtx: WorkspaceContext,
	entries: Array<{ repo: RepoTarget; available: boolean; isActive: boolean }>,
): string {
	const lines = [
		"# /spec repo status",
		"",
		`- Workspace root: ${wsCtx.workspaceRoot}`,
		`- Multi-repo mode: ${wsCtx.isMultiRepo ? "yes" : "no"}`,
		`- Registered repositories: ${entries.length}`,
	];

	if (wsCtx.activeRepo) {
		lines.push(`- Active repository: ${wsCtx.activeRepo.name} (${wsCtx.activeRepo.path})`);
	} else if (entries.length > 1) {
		lines.push("- Active repository: (none) — run `/spec repo use <name>` to select");
	} else if (entries.length === 0) {
		lines.push("- No repositories registered. Run `/spec repo add <path> [name]` to add one.");
	}

	const unavailable = entries.filter((e) => !e.available);
	if (unavailable.length > 0) {
		lines.push("");
		lines.push("## Unavailable repositories");
		for (const e of unavailable) {
			lines.push(`- ${e.repo.name}: ${e.repo.path} (path not found)`);
		}
	}

	return lines.join("\n");
}

import { existsSync, mkdirSync, readdirSync, statSync } from "node:fs";
import path from "node:path";
import type { GitClient } from "./git.js";
import type { PreparedFeature, WorkflowPaths } from "./types.js";

/**
 * Find the workspace root by scanning upward from cwd for a `.specify/` directory.
 * This is independent of git root detection — the workspace root is the directory
 * that owns the `.specify/` configuration.
 * Returns null if no `.specify/` directory is found.
 */
export function findWorkspaceRoot(cwd: string): string | null {
	let current = path.resolve(cwd);
	while (true) {
		if (existsSync(path.join(current, ".specify"))) {
			return current;
		}
		const parent = path.dirname(current);
		if (parent === current) {
			return null;
		}
		current = parent;
	}
}

