// Linear Integration Types

/**
 * Metadata for a Linear Issue associated with a feature
 */
export interface LinearIssueMetadata {
	issueId: string; // Linear internal ID (UUID)
	issueKey: string; // Display key (e.g., "SCH-1234")
	teamKey: string; // Team identifier (e.g., "SCH")
	lastSync: string; // ISO 8601 timestamp
	specHash: string; // SHA-256 hash of spec.md content
}

/**
 * Metadata for a Linear Sub-Issue associated with a task
 */
export interface LinearTaskMetadata {
	taskId: string; // Task identifier (e.g., "T001")
	linearSubIssueId: string; // Linear internal ID
	linearSubIssueKey: string; // Display key (e.g., "SCH-5678")
	lastSync: string; // ISO 8601 timestamp
	taskHash: string; // SHA-256 hash of task content
	isComplete?: boolean; // Completion status from last sync
}

/**
 * Root metadata file for Linear integration
 */
export interface LinearMetadata {
	$schema?: string; // JSON Schema reference
	version: string; // Metadata format version (e.g., "1.0")
	featureId: string; // Feature directory name
	linear?: LinearIssueMetadata; // Present when feature is synced
	tasks: LinearTaskMetadata[]; // Task sync metadata
}

/**
 * Parsed task from tasks.md
 */
export interface ParsedTask {
	id: string; // Task identifier (e.g., "T001")
	title: string; // Task title
	description: string; // Full task description (markdown)
	isComplete: boolean; // Completion status from checkbox
	rawContent: string; // Original markdown content
}

/**
 * Content change during sanitization
 */
export interface ContentChange {
	type: "absolute-path-removed" | "absolute-path-relativized" | "artifact-reference-removed";
	original: string; // What was changed
	replacement: string; // What it became
	line?: number; // Optional line number
}

/**
 * Sanitized content result
 */
export interface SanitizedContent {
	original: string; // Original markdown
	sanitized: string; // Processed content
