import { createHash } from "node:crypto";
import { existsSync, readdirSync, readFileSync, statSync } from "node:fs";
import path from "node:path";
import type {
	ContractChecksum,
	ContractDrift,
	CrossRepoDeclaration,
	RepoDeclaration,
	RepoRegistry,
	RepoTaggedTask,
} from "./types.js";

/**
 * Parse the `## Repositories` markdown table from spec content.
 * Returns a CrossRepoDeclaration with isCrossRepo=true if ≥2 repos declared.
 */
export function parseRepositoriesTable(specContent: string): CrossRepoDeclaration {
	const empty: CrossRepoDeclaration = { repos: [], isCrossRepo: false };

	// Find the ## Repositories section
	const sectionMatch = specContent.match(/^## Repositories\s*$/m);
	if (!sectionMatch || sectionMatch.index === undefined) {
		return empty;
	}

	// Extract content after the heading until the next ## heading or end
	const afterHeading = specContent.slice(sectionMatch.index + sectionMatch[0].length);
	const nextSection = afterHeading.search(/^## /m);
	const sectionContent = nextSection >= 0 ? afterHeading.slice(0, nextSection) : afterHeading;

	// Extract table rows
	const rowRegex = /^\|\s*([^|]+?)\s*\|\s*([^|]+?)\s*\|\s*([^|]+?)\s*\|$/gm;
	const repos: RepoDeclaration[] = [];

	let match: RegExpExecArray | null;
	while ((match = rowRegex.exec(sectionContent)) !== null) {
		const [, name, role, description] = match;
		// Skip header row and separator row
		if (name.trim().toLowerCase() === "repo" || name.trim().includes("---")) {
			continue;
		}
		if (role.trim().includes("---")) {
			continue;
		}
		const trimmedName = name.trim();
		if (trimmedName.length > 0) {
			repos.push({
				name: trimmedName,
				role: role.trim(),
				description: description.trim(),
			});
		}
	}

	return {
		repos,
		isCrossRepo: repos.length >= 2,
	};
}

/**
 * Extract the repo tag from a task line.
 * Tag order is: [P?] [RepoName] [USn]
 * Returns the repo name or null if no repo tag found.
 *
 * When a declaration is provided, validates the extracted tag against
 * declared repo names. If it doesn't match, treats it as a non-repo tag.
 */
export function extractRepoTag(
	taskLine: string,
	declaration?: CrossRepoDeclaration,
): string | null {
	// Extract all bracket tokens from the task line
	const bracketTokens = taskLine.match(/\[([^\]]+)\]/g);
	if (!bracketTokens) {
		return null;
	}

	const declaredNames = declaration
		? new Set(declaration.repos.map((r) => r.name.toLowerCase()))
		: null;

	for (const token of bracketTokens) {
		const inner = token.slice(1, -1).trim();

		// Skip known non-repo tokens
		if (inner === "P" || inner === "p") continue;
		if (/^US\d+$/i.test(inner)) continue;
		if (inner === " " || inner === "x" || inner === "X") continue; // checkbox

		// If we have a declaration, validate against it
		if (declaredNames) {
			if (declaredNames.has(inner.toLowerCase())) {
				return inner;
			}
			// Not a declared repo — skip (could be a custom tag like [BLOCKED])
			continue;
		}

		// No declaration — return first non-P, non-US token that starts with a letter
		if (/^[A-Za-z][A-Za-z0-9_-]*$/.test(inner)) {
			return inner;
		}
	}

	return null;
}

/**
 * Parse all task lines from tasks.md content and extract repo tags.
 */
export function parseRepoTaggedTasks(
	tasksContent: string,
	declaration?: CrossRepoDeclaration,
): RepoTaggedTask[] {
	const lines = tasksContent.split(/\r?\n/);
	const tasks: RepoTaggedTask[] = [];

	for (const line of lines) {
		const taskMatch = line.match(/^- \[([ xX])\]\s+(T\d{3}\w*)\s/);
		if (!taskMatch) continue;

		tasks.push({
			id: taskMatch[2],
			repoTag: extractRepoTag(line, declaration),
			isComplete: taskMatch[1].toLowerCase() === "x",
			rawLine: line,
		});
	}

	return tasks;
}

/**
 * Validate that repo names in a declaration match registered repos.
 * Returns an array of warning strings for unmatched names.
 */
export function validateRepoNames(
	declaration: CrossRepoDeclaration,
	registry: RepoRegistry,
): string[] {
	const warnings: string[] = [];
	const registeredNames = new Set(
		registry.repositories.map((r) => r.name.toLowerCase()),
	);

	for (const repo of declaration.repos) {
		if (!registeredNames.has(repo.name.toLowerCase())) {
			warnings.push(
				`Repo '${repo.name}' in spec is not registered. Run \`/spec repo add\` to register it.`,
			);
		}
	}

	return warnings;
}

/**
 * Produce a markdown block listing repos/roles for prompt injection.
 */
export function injectCrossRepoContext(declaration: CrossRepoDeclaration): string {
	if (!declaration.isCrossRepo) return "";

	const lines = [
		"## Cross-repo feature",
		"",
		"This feature spans multiple repositories. Every task MUST be tagged with a `[RepoName]`.",
		"",
		"| Repo | Role | Description |",
		"|------|------|-------------|",
	];

	for (const repo of declaration.repos) {
		lines.push(`| ${repo.name} | ${repo.role} | ${repo.description} |`);
	}

	return lines.join("\n");
}

// ── Contract checksums ────────────────────────────────────────────────────

/**
 * Compute SHA-256 checksums for all files in a contracts directory.
 */
export function computeContractChecksums(contractsDir: string): ContractChecksum[] {
	if (!existsSync(contractsDir) || !statSync(contractsDir).isDirectory()) {
		return [];
	}

	const checksums: ContractChecksum[] = [];
	const entries = readdirSync(contractsDir).sort();

	for (const entry of entries) {
		const fullPath = path.join(contractsDir, entry);
		if (!statSync(fullPath).isFile()) continue;

		const content = readFileSync(fullPath, "utf8");
		const hash = createHash("sha256").update(content).digest("hex");
		checksums.push({ filePath: entry, sha256: hash });
	}

	return checksums;
}

/**
 * Format checksums as an HTML comment block for appending to tasks.md.
 */
export function formatContractChecksumBlock(checksums: ContractChecksum[]): string {
	if (checksums.length === 0) return "";

	const lines = ["<!-- contract-checksums"];
	for (const cs of checksums) {
		lines.push(`${cs.filePath}:${cs.sha256}`);
	}
	lines.push("-->");
	return lines.join("\n");
}

/**
 * Parse checksums from an existing tasks.md comment block.
 */
export function parseContractChecksums(tasksContent: string): ContractChecksum[] {
	const match = tasksContent.match(/<!-- contract-checksums\n([\s\S]*?)-->/);
	if (!match) return [];

	const lines = match[1].trim().split(/\r?\n/);
	const checksums: ContractChecksum[] = [];

	for (const line of lines) {
		const colonIndex = line.lastIndexOf(":");
		if (colonIndex <= 0) continue;
		checksums.push({
			filePath: line.slice(0, colonIndex),
			sha256: line.slice(colonIndex + 1),
		});
	}

	return checksums;
}

/**
 * Compare current contract checksums against stored ones.
 */
export function detectContractDrift(
	current: ContractChecksum[],
	stored: ContractChecksum[],
): ContractDrift {
	const currentMap = new Map(current.map((c) => [c.filePath, c.sha256]));
	const storedMap = new Map(stored.map((c) => [c.filePath, c.sha256]));

	const changed: string[] = [];
	const added: string[] = [];
	const removed: string[] = [];

	// Check for changed and added
	for (const [filePath, hash] of currentMap) {
		const storedHash = storedMap.get(filePath);
		if (storedHash === undefined) {
			added.push(filePath);
		} else if (storedHash !== hash) {
			changed.push(filePath);
		}
	}

	// Check for removed
	for (const filePath of storedMap.keys()) {
		if (!currentMap.has(filePath)) {
			removed.push(filePath);
		}
	}

	return {
		changed,
		added,
		removed,
		hasDrift: changed.length > 0 || added.length > 0 || removed.length > 0,
	};
}

import { extractRepoTag, parseRepoTaggedTasks } from "./cross-repo-parser.js";
import type { CrossRepoDeclaration, CrossRepoProgress, RepoTaggedTask } from "./types.js";

/**
 * Compute per-repo task completion progress from tasks.md content.
 */
export function computeCrossRepoProgress(
	tasksContent: string,
	declaration: CrossRepoDeclaration,
): CrossRepoProgress {
	const tasks = parseRepoTaggedTasks(tasksContent, declaration);

	const repoProgress = new Map<string, { total: number; completed: number }>();

	// Initialize from declaration so repos with 0 tasks still appear
	for (const repo of declaration.repos) {
		repoProgress.set(repo.name, { total: 0, completed: 0 });
	}

	for (const task of tasks) {
		if (!task.repoTag) continue;
		const entry = repoProgress.get(task.repoTag) ?? { total: 0, completed: 0 };
		entry.total++;
		if (task.isComplete) entry.completed++;
		repoProgress.set(task.repoTag, entry);
	}

	let overallTotal = 0;
	let overallCompleted = 0;
	for (const { total, completed } of repoProgress.values()) {
		overallTotal += total;
		overallCompleted += completed;
	}

	return { repoProgress, overallTotal, overallCompleted };
}

/**
 * Render a markdown progress table.
 */
export function formatCrossRepoProgress(progress: CrossRepoProgress): string {
	if (progress.repoProgress.size === 0) {
		return "";
	}

	const lines = [
		"## Cross-repo progress",
		"",
		"| Repo | Tasks | Complete | Remaining |",
		"|------|-------|----------|-----------|",
	];

	for (const [name, { total, completed }] of progress.repoProgress) {
		const remaining = total - completed;
		const check = completed === total && total > 0 ? " ✓" : "";
		lines.push(`| ${name} | ${total} | ${completed}${check} | ${remaining} |`);
	}

	lines.push(
		"",
		`**Overall**: ${progress.overallCompleted}/${progress.overallTotal} tasks complete`,
	);

	return lines.join("\n");
}

/**
 * Format cross-repo status section (repos + roles + warnings).
 */
export function formatCrossRepoStatus(
	declaration: CrossRepoDeclaration,
	warnings: string[],
): string {
	if (!declaration.isCrossRepo) return "";

	const lines = [
		"## Cross-repo feature",
		"",
		"| Repo | Role |",
		"|------|------|",
	];

	for (const repo of declaration.repos) {
		lines.push(`| ${repo.name} | ${repo.role} |`);
	}

	if (warnings.length > 0) {
		lines.push("");
		for (const w of warnings) {
			lines.push(`⚠️ ${w}`);
		}
	}

	return lines.join("\n");
}

/**
 * Filter task lines by active repo. Returns matching lines and skipped task IDs.
 */
export function filterTasksByRepo(
	tasksContent: string,
	activeRepoName: string,
	declaration?: CrossRepoDeclaration,
): { matching: string[]; skippedIds: string[] } {
	const lines = tasksContent.split(/\r?\n/);
	const matching: string[] = [];
	const skippedIds: string[] = [];

	for (const line of lines) {
		const taskMatch = line.match(/^- \[([ xX])\]\s+(T\d{3}\w*)\s/);
		if (!taskMatch) continue;

		const tag = extractRepoTag(line, declaration);
		if (tag && tag.toLowerCase() === activeRepoName.toLowerCase()) {
			matching.push(line);
		} else if (tag) {
			skippedIds.push(taskMatch[2]);
		}
	}

	return { matching, skippedIds };
}

/**
 * Count tasks that would be skipped for the active repo.
 */
export function countSkippedTasks(
	tasksContent: string,
	activeRepoName: string,
	declaration?: CrossRepoDeclaration,
): number {
	return filterTasksByRepo(tasksContent, activeRepoName, declaration).skippedIds.length;
}

/**
 * Generate cross-repo-aware next step suggestions.
 */
export function crossRepoNextSteps(
	progress: CrossRepoProgress,
	declaration: CrossRepoDeclaration,
): string[] {
	const steps: string[] = [];

	const incomplete: string[] = [];
	const complete: string[] = [];

	for (const [name, { total, completed }] of progress.repoProgress) {
		if (completed < total) {
			incomplete.push(name);
		} else if (total > 0) {
			complete.push(name);
		}
	}

	if (incomplete.length > 1) {
		steps.push(
			`Parallel: repos ${incomplete.join(", ")} have remaining tasks — switch with \`/spec repo use <name>\` and run \`/spec implement\``,
		);
	} else if (incomplete.length === 1) {
		steps.push(
			`Continue: \`/spec repo use ${incomplete[0]}\` then \`/spec implement\``,
		);
	}

	if (complete.length > 0 && incomplete.length > 0) {
		steps.push(
			`Completed: ${complete.join(", ")} — all tasks done`,
		);
	}

	if (progress.overallCompleted === progress.overallTotal && progress.overallTotal > 0) {
		steps.push("All cross-repo tasks complete! 🎉");
	}

	return steps;
}

