// Cross-repo context injection (T026, T032, T033, T021b)
if (context.crossRepo?.isCrossRepo) {
	const crContext = injectCrossRepoContext(context.crossRepo);
	if (crContext) {
		lines.push("", crContext);
	}

	// T033: Active repo filtering for implement
	if (context.step === "implement" && context.paths.tasksFile && existsSync(context.paths.tasksFile)) {
		// Extract active repo name from step notes (injected by getStepNotes)
		const activeRepoNote = context.stepNotes.find((n) => n.startsWith("Active repo:"));
		if (activeRepoNote) {
			const activeRepoName = activeRepoNote.replace("Active repo: ", "").split(".")[0].trim();
			const tasksContent = readFileSync(context.paths.tasksFile, "utf8");
			const { matching, skippedIds } = filterTasksByRepo(tasksContent, activeRepoName, context.crossRepo);
			lines.push("", "## Active repo filtering");
			lines.push(`- Active repository: ${activeRepoName}`);
			lines.push(`- Tasks to execute: ${matching.length}`);
			lines.push(`- Tasks to skip (different repo): ${skippedIds.length}${skippedIds.length > 0 ? ` (${skippedIds.join(", ")})` : ""}`);
		}
	}

	// T021b: Contract drift for analyze
	if (context.step === "analyze" && context.paths.contractsDir && context.paths.tasksFile) {
		const currentChecksums = computeContractChecksums(context.paths.contractsDir);
		if (existsSync(context.paths.tasksFile)) {
			const tasksContent = readFileSync(context.paths.tasksFile, "utf8");
			const storedChecksums = parseContractChecksums(tasksContent);
			if (storedChecksums.length > 0) {
				const drift = detectContractDrift(currentChecksums, storedChecksums);
				lines.push("", "## Contract drift");
				if (drift.hasDrift) {
					if (drift.changed.length > 0) lines.push(`- Changed: ${drift.changed.join(", ")}`);
					if (drift.added.length > 0) lines.push(`- Added: ${drift.added.join(", ")}`);
					if (drift.removed.length > 0) lines.push(`- Removed: ${drift.removed.join(", ")}`);
					lines.push("- ⚠️ Contracts have changed since tasks were generated. Consider regenerating tasks with `/spec tasks`.");
				} else {
					lines.push("- No contract drift detected. Contracts match the task generation baseline.");
				}
			} else {
				lines.push("", "## Contract drift", "- No baseline checksums found in tasks.md. Cannot compare.");
			}
		}
	}
}

