function queueWorkflow(
	pi: ExtensionAPI,
	step: WorkflowStep,
	currentBranch: string,
	paths: WorkflowPaths,
	input: string,
	options?: { crossRepo?: CrossRepoDeclaration; activeRepoName?: string },
): void {
	const stepNotes = [...getStepNotes(step)];

	// T027/T028: Add cross-repo step notes
	if (options?.crossRepo?.isCrossRepo) {
		if (step === "tasks") {
			stepNotes.push(
				"This is a cross-repo feature. Tag every task with `[RepoName]`. Generate parallel phases per repo. Every task MUST have a repo tag — no exceptions.",
			);
		}
		if (step === "implement") {
			stepNotes.push("Filter tasks by active repo. Skip tasks tagged for other repos with a \"skipped (different repo)\" note.");
			if (options.activeRepoName) {
				stepNotes.push(`Active repo: ${options.activeRepoName}. Execute only [${options.activeRepoName}] tasks.`);
			}
		}
		if (step === "analyze") {
			stepNotes.push("This is a cross-repo feature. Check for contract drift and validate that all tasks have repo tags.");
		}
	}

	const prompt = buildWorkflowPrompt({
		step,
		input,
		paths,
		currentBranch,
		workflowTemplatePath: getWorkflowTemplatePath(paths, step),
		stepNotes,
		checklists: step === "implement" ? summarizeChecklists(paths.checklistsDir) : undefined,
		crossRepo: options?.crossRepo,
	});
	pi.sendUserMessage(prompt);
}

