/**
 * Ensure contract checksums are appended to tasks.md for a cross-repo feature.
 * This is idempotent: if the checksum block already exists, it does nothing.
 * Called lazily from steps that run after `/spec tasks` (analyze, implement, status).
 */
export function ensureContractChecksums(
	tasksFilePath: string,
	contractsDir: string,
): { appended: boolean; checksums: ContractChecksum[] } {
	if (!existsSync(tasksFilePath) || !existsSync(contractsDir)) {
		return { appended: false, checksums: [] };
	}

	const tasksContent = readFileSync(tasksFilePath, "utf8");

	// Already has checksums — skip
	if (tasksContent.includes("<!-- contract-checksums")) {
		return { appended: false, checksums: parseContractChecksums(tasksContent) };
	}

	const checksums = computeContractChecksums(contractsDir);
	if (checksums.length === 0) {
		return { appended: false, checksums: [] };
	}

	const block = formatContractChecksumBlock(checksums);
	appendFileSync(tasksFilePath, `\n\n${block}\n`, "utf8");
	return { appended: true, checksums };
}

