/**
 * Discover and auto-register a repo by name.
 * Looks for `<workspaceRoot>/<name>` as a sibling directory.
 * If already registered (case-insensitive), returns the existing entry.
 * If found as sibling, calls addRepository to register.
 * If not found, throws with a helpful message.
 */
export function discoverAndRegisterRepo(
	workspaceRoot: string,
	name: string,
): RepoTarget {
	// Don't register workspace root itself
	if (path.basename(path.resolve(workspaceRoot)) === name) {
		throw new Error(
			`Cannot register '${name}' — it is the workspace root directory itself.`,
		);
	}

	// Check if already registered
	const registry = readRegistry(workspaceRoot);
	if (registry) {
		const existing = registry.repositories.find(
			(r) => r.name.toLowerCase() === name.toLowerCase(),
		);
		if (existing) {
			return existing;
		}
	}

	// Try sibling directory
	const candidatePath = path.join(workspaceRoot, name);
	if (existsSync(candidatePath) && statSync(candidatePath).isDirectory()) {
		const { added } = addRepository(workspaceRoot, candidatePath, name);
		return added;
	}

	throw new Error(
		`Repository '${name}' not found as a sibling directory of the workspace root (${workspaceRoot}/${name}).\n` +
			`Register it manually with: /spec repo add <path> ${name}`,
	);
}

/**
 * Batch discover and register multiple repos by name.
 * Stops on first error.
 */
export function discoverAndRegisterRepos(
	workspaceRoot: string,
	names: string[],
): RepoTarget[] {
	const results: RepoTarget[] = [];
	for (const name of names) {
		results.push(discoverAndRegisterRepo(workspaceRoot, name));
	}
	return results;
}

