describe("discoverAndRegisterRepo", () => {
	it("auto-registers a sibling directory", () => {
		const ws = createWorkspace();
		const sibling = path.join(ws, "my-repo");
		require("node:fs").mkdirSync(sibling, { recursive: true });

		const result = discoverAndRegisterRepo(ws, "my-repo");
		expect(result.name).toBe("my-repo");
		expect(result.path).toBe(sibling);
		// Should be in registry now
		const reg = readRegistry(ws);
		expect(reg!.repositories).toHaveLength(1);
	});

	it("returns existing entry if already registered (no duplicate)", () => {
		const ws = createWorkspace();
		const repo = createRepo("already");
		addRepository(ws, repo, "Already");

		// Discover with same name
		const result = discoverAndRegisterRepo(ws, "Already");
		expect(result.name).toBe("Already");
		// Still only 1 entry
		expect(readRegistry(ws)!.repositories).toHaveLength(1);
	});

	it("throws when sibling directory not found", () => {
		const ws = createWorkspace();
		expect(() => discoverAndRegisterRepo(ws, "nonexistent")).toThrow(/not found as a sibling/);
	});

	it("throws when name is the workspace root basename", () => {
		const ws = createWorkspace();
		const wsName = path.basename(ws);
		expect(() => discoverAndRegisterRepo(ws, wsName)).toThrow(/workspace root directory itself/);
	});
});

