async function handleSpecify(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
	input: string,
): Promise<void> {
	if (!input) {
		ctx.ui.notify("/spec specify requires a feature description.", "warning");
		return;
	}

	// Prompt for repo names before running the specify workflow
	let repoNames: string[] = [];
	if (ctx.hasUI && typeof ctx.ui.input === "function") {
		const repoInput = await ctx.ui.input(
			"Repository names (comma-separated)",
			env.wsCtx.activeRepo?.name ?? "e.g. core-payrolls, core-bookings",
		);
		repoNames = parseRepoNamesInput(repoInput ?? "");
	}

	// If no UI or user provided nothing, default to active repo (if any)
	if (repoNames.length === 0 && env.wsCtx.activeRepo) {
		repoNames = [env.wsCtx.activeRepo.name];
	}

	// Auto-register repos via sibling directory discovery
	if (repoNames.length > 0) {
		try {
			discoverAndRegisterRepos(env.wsCtx.workspaceRoot, repoNames);
		} catch (error) {
			ctx.ui.notify(
				`Failed to register repositories: ${error instanceof Error ? error.message : String(error)}`,
				"error",
			);
			return;
		}
	}

	// Determine target root: workspaceRoot if cross-repo (≥2), repoRoot if single
	const isCrossRepo = repoNames.length >= 2;
	const targetRoot = isCrossRepo ? env.wsCtx.workspaceRoot : undefined;

	try {
		const prepared = prepareFeatureWorkspace({
			repoRoot: env.repoRoot,
			description: input,
			git: env.git,
			currentBranch: env.currentBranch,
			hasGit: env.hasGit,
			targetRoot,
		});
		const paths = buildWorkflowPaths(
			targetRoot ?? env.repoRoot,
			prepared.branchName,
			env.wsCtx.workspaceRoot,
		);
		ensureWorkflowScaffold(paths);
		ensureFeatureArtifacts(paths);

		// Inject ## Repositories table into spec.md
		if (repoNames.length > 0 && paths.featureSpec && existsSync(paths.featureSpec)) {
			const table = generateRepositoriesTable(repoNames);
			if (table) {
				const specContent = readFileSync(paths.featureSpec, "utf8");
				// Insert after the header block (first ---\n or after **Input**: line)
				const insertPoint = specContent.indexOf("\n## ");
				if (insertPoint >= 0) {
					const updated = `${specContent.slice(0, insertPoint)}\n\n${table}\n${specContent.slice(insertPoint)}`;
					const { writeFileSync: wfs } = await import("node:fs");
					wfs(paths.featureSpec, updated, "utf8");
				}
			}
		}

		queueWorkflow(pi, "specify", prepared.branchName, paths, input);
		sendReport(
			pi,
			[
				"# /spec specify",
				"",
				`- Feature branch: ${prepared.branchName}`,
				`- Feature number: ${prepared.featureNumber}`,
				`- Feature directory: ${prepared.featureDir}`,
				`- Spec file: ${prepared.specFile}`,
				`- Repositories: ${repoNames.join(", ") || "(none provided)"}`,
				isCrossRepo ? "- Cross-repo feature: yes" : "",
				env.wsCtx.isMultiRepo ? `- Active repository: ${env.wsCtx.activeRepo?.name ?? "(none)"}` : "",
				"",
				"Queued the native specification workflow as a user message.",
			].filter(Boolean).join("\n"),
		);
	} catch (error) {
		ctx.ui.notify(
			`Failed to prepare feature workspace: ${error instanceof Error ? error.message : String(error)}`,
			"error",
		);
	}
}

